"use client"

import * as React from "react"
import { useMemo, useCallback } from "react"
import { cn } from "@/lib/utils"
import type {
  CalendarEvent,
  CalendarProps,
  View,
  NavigateAction,
  Accessors,
  Getters,
  CalendarComponents,
  DateLocalizer,
} from "./types"
import { navigate, views } from "./constants"
import { wrapAccessor, mergeMessages } from "./helpers"
import { useControllableState } from "./hooks/use-controllable-state"
import { CalendarProvider } from "./calendar-context"
import { DnDProvider } from "./hooks/use-dnd"
import { Toolbar } from "./components/toolbar"
import { Header, DateHeader, ResourceHeader } from "./components/headers"
import { EventDetailSheet } from "./components/event-detail-sheet"
import { NoopWrapper } from "./helpers"

// Views
import { MonthView } from "./views/month"
import { WeekView } from "./views/week"
import { DayView } from "./views/day"
import { WorkWeekView } from "./views/work-week"
import { AgendaView } from "./views/agenda"

// ─── Default view map ──────────────────────────────────────────────
const VIEWS: Record<string, React.ComponentType<any>> = {
  [views.MONTH]: MonthView,
  [views.WEEK]: WeekView,
  [views.WORK_WEEK]: WorkWeekView,
  [views.DAY]: DayView,
  [views.AGENDA]: AgendaView,
}

// ─── Default messages ──────────────────────────────────────────────
const defaultMessages = {
  date: "Date",
  time: "Time",
  event: "Event",
  allDay: "All Day",
  week: "Week",
  work_week: "Work Week",
  day: "Day",
  month: "Month",
  agenda: "Agenda",
  previous: "Back",
  next: "Next",
  today: "Today",
  noEventsInRange: "There are no events in this range.",
  showMore: (total: number) => `+${total} more`,
}

// ─── Calendar ──────────────────────────────────────────────────────

export function Calendar<TEvent extends CalendarEvent = CalendarEvent>({
  events = [] as unknown as TEvent[],
  backgroundEvents = [] as unknown as TEvent[],
  date: dateProp,
  defaultDate,
  view: viewProp,
  defaultView = views.MONTH as View,
  onNavigate,
  onView,
  getNow = () => new Date(),
  localizer,

  // Event accessors
  titleAccessor = "title" as keyof TEvent,
  tooltipAccessor = "title" as keyof TEvent,
  startAccessor = "start" as keyof TEvent,
  endAccessor = "end" as keyof TEvent,
  allDayAccessor = "allDay" as keyof TEvent,
  resourceAccessor,
  resourceIdAccessor,
  resourceTitleAccessor,
  resources,

  // Behavior
  selectable = false,
  longPressThreshold = 250,
  step = 30,
  timeslots = 2,
  min: minProp,
  max: maxProp,
  scrollToTime,
  rtl = false,
  popup = false,
  popupOffset,
  length = 30,
  dayLayoutAlgorithm = "overlap",

  // Style getters
  eventPropGetter,
  slotPropGetter,
  slotGroupPropGetter,
  dayPropGetter,

  // Callbacks
  onSelectEvent,
  onDoubleClickEvent,
  onKeyPressEvent,
  onSelectSlot,
  onDrillDown: onDrillDownProp,
  onRangeChange,
  onShowMore,

  // Zoom
  onZoomIn,
  onZoomOut,
  canZoomIn,
  canZoomOut,

  // Drag & Drop
  draggable = false,
  draggableAccessor,
  resizableAccessor,
  onEventDrop,
  onEventResize,
  onDragStart,
  onDragEnd,
  dragFromOutsideItem: _dragFromOutsideItem,

  // Event Detail Sheet
  onEventSave,
  onEventDelete,
  eventDetailContent,
  eventDetailSide = "right",

  // Component overrides
  components: componentsProp = {} as Partial<CalendarComponents<TEvent>>,

  // Messages
  messages: messagesProp,

  // Views override
  views: viewsProp = [views.MONTH, views.WEEK, views.WORK_WEEK, views.DAY, views.AGENDA] as View[],

  // Toolbar
  toolbar = true,

  // Declared but not yet implemented (destructured to keep out of DOM)
  formats: _formats,
  selected: _selected,
  enableAutoScroll: _enableAutoScroll,
  showMultiDayTimes: _showMultiDayTimes,
  allDayMaxRows: _allDayMaxRows,
  showAllEvents: _showAllEvents,
  doShowMoreDrillDown: _doShowMoreDrillDown,
  drilldownView: _drilldownView,
  getDrilldownView: _getDrilldownView,
  eventIdAccessor: _eventIdAccessor,
  resourceGroupingLayout: _resourceGroupingLayout,
  culture: _culture,

  // Classname
  className,
  style,

  // Extra props (elementProps)
  ...elementProps
}: CalendarProps<TEvent>) {
  // Controllable state for date and view
  // ── Event detail sheet state ──
  const [sheetEvent, setSheetEvent] = React.useState<TEvent | null>(null)
  const sheetOpen = sheetEvent !== null

  const [currentDate, setCurrentDate] = useControllableState<Date>(
    dateProp,
    defaultDate || getNow(),
    (d: Date) => onNavigate?.(d, currentView ?? defaultView, navigate.DATE as NavigateAction),
  )

  const [currentView, setCurrentView] = useControllableState<View>(
    viewProp,
    defaultView,
    (v: View) => onView?.(v),
  )

  // Build accessors
  const accessors: Accessors<TEvent> = useMemo(
    () => ({
      title: wrapAccessor(titleAccessor),
      tooltip: wrapAccessor(tooltipAccessor),
      start: wrapAccessor(startAccessor),
      end: wrapAccessor(endAccessor),
      allDay: wrapAccessor(allDayAccessor),
      resource: resourceAccessor ? wrapAccessor(resourceAccessor) : undefined,
    }),
    [titleAccessor, tooltipAccessor, startAccessor, endAccessor, allDayAccessor, resourceAccessor],
  )

  // Build getters
  const getters: Getters<TEvent> = useMemo(
    () => ({
      eventProp: (event, start, end, isSelected) =>
        eventPropGetter?.(event, start, end, isSelected) ?? {},
      slotProp: (date, resourceId) =>
        slotPropGetter?.(date, resourceId) ?? {},
      slotGroupProp: () => slotGroupPropGetter?.() ?? {},
      dayProp: (date) => dayPropGetter?.(date) ?? {},
    }),
    [eventPropGetter, slotPropGetter, slotGroupPropGetter, dayPropGetter],
  )

  // Build components
  const calendarComponents: CalendarComponents<TEvent> = useMemo(
    () => ({
      event: componentsProp.event,
      eventWrapper: componentsProp.eventWrapper ?? NoopWrapper,
      dayWrapper: componentsProp.dayWrapper ?? NoopWrapper,
      dateCellWrapper: componentsProp.dateCellWrapper ?? NoopWrapper,
      timeSlotWrapper: componentsProp.timeSlotWrapper ?? NoopWrapper,
      timeGutterHeader: componentsProp.timeGutterHeader,
      resourceHeader: componentsProp.resourceHeader ?? ResourceHeader,
      toolbar: componentsProp.toolbar ?? Toolbar,
      header: componentsProp.header ?? Header,
      week: componentsProp.week,
      day: componentsProp.day,
      month: componentsProp.month,
      agenda: componentsProp.agenda,
      eventDetailSheet: componentsProp.eventDetailSheet,
    }),
    [componentsProp],
  )

  // Messages
  const messages = useMemo(
    () => mergeMessages(defaultMessages, messagesProp),
    [messagesProp],
  )

  // Resolve the active view component
  const viewNamesMap = useMemo(() => {
    if (Array.isArray(viewsProp)) {
      const map: Record<string, React.ComponentType<any>> = {}
      for (const v of viewsProp) {
        map[v] = VIEWS[v]
      }
      return map
    }
    return viewsProp as Record<string, React.ComponentType<any>>
  }, [viewsProp])

  const ViewComponent = viewNamesMap[currentView] ?? MonthView
  const viewNames = Object.keys(viewNamesMap) as View[]

  // Navigation handler
  const handleNavigate = useCallback(
    (action: NavigateAction, newDate?: Date) => {
      let nextDate = newDate || currentDate

      if (action === navigate.TODAY) {
        nextDate = getNow()
      } else if (action === navigate.DATE) {
        nextDate = newDate || currentDate
      } else {
        const viewComponent = ViewComponent as any
        if (viewComponent.navigate) {
          nextDate = viewComponent.navigate(currentDate, action, localizer)
        }
      }

      setCurrentDate(nextDate)
      onNavigate?.(nextDate, currentView, action)

      const viewComponent = ViewComponent as any
      if (onRangeChange && viewComponent.range) {
        const range = viewComponent.range(nextDate, localizer)
        onRangeChange(
          Array.isArray(range) ? range : [range.start, range.end],
          currentView,
        )
      }
    },
    [currentDate, currentView, getNow, localizer, ViewComponent, setCurrentDate, onNavigate, onRangeChange],
  )

  // View change handler
  const handleViewChange = useCallback(
    (newView: View) => {
      setCurrentView(newView)
      onView?.(newView)
    },
    [setCurrentView, onView],
  )

  // Double-click handler (open event detail sheet)
  const handleDoubleClickEvent = useCallback(
    (event: TEvent, e: React.SyntheticEvent) => {
      // Open the detail sheet
      setSheetEvent(event)
      // Also fire the user's callback if provided
      onDoubleClickEvent?.(event, e)
    },
    [onDoubleClickEvent],
  )

  // Sheet save handler
  const handleSheetSave = useCallback(
    (updatedEvent: TEvent, originalEvent: TEvent) => {
      onEventSave?.(updatedEvent, originalEvent)
      setSheetEvent(null)
    },
    [onEventSave],
  )

  // Sheet delete handler
  const handleSheetDelete = useCallback(
    (event: TEvent) => {
      onEventDelete?.(event)
      setSheetEvent(null)
    },
    [onEventDelete],
  )

  // Drill down handler
  const handleDrillDown = useCallback(
    (date: Date, view?: string) => {
      if (onDrillDownProp) {
        onDrillDownProp(date, view || views.DAY)
      } else {
        const targetView = (view || views.DAY) as View
        if (viewNamesMap[targetView]) {
          handleViewChange(targetView)
          setCurrentDate(date)
        }
      }
    },
    [onDrillDownProp, viewNamesMap, handleViewChange, setCurrentDate],
  )

  // Title for toolbar
  const viewComponent = ViewComponent as any
  const label = viewComponent.title
    ? viewComponent.title(currentDate, localizer, length)
    : ""

  // Default min/max for time-based views
  const minDate = useMemo(() => {
    if (minProp) return minProp
    const d = new Date()
    d.setHours(0, 0, 0, 0)
    return d
  }, [minProp])

  const maxDate = useMemo(() => {
    if (maxProp) return maxProp
    const d = new Date()
    d.setHours(23, 59, 59, 999)
    return d
  }, [maxProp])

  // Resources
  const resourceList = useMemo(() => {
    if (!resources) return undefined
    const getId = typeof resourceIdAccessor === 'function'
      ? resourceIdAccessor
      : (r: Record<string, unknown>) => r[resourceIdAccessor as string ?? 'id'] as string | number
    const getTitle = typeof resourceTitleAccessor === 'function'
      ? resourceTitleAccessor
      : (r: Record<string, unknown>) => r[resourceTitleAccessor as string ?? 'title'] as string
    return resources.map((r) => ({
      id: getId(r as any),
      title: getTitle(r as any),
    }))
  }, [resources, resourceIdAccessor, resourceTitleAccessor])

  return (
    <DnDProvider
      enabled={draggable}
      draggableAccessor={draggableAccessor}
      resizableAccessor={resizableAccessor}
      onEventDrop={onEventDrop}
      onEventResize={onEventResize}
      onDragStart={onDragStart}
      onDragEnd={onDragEnd}
    >
    <CalendarProvider
      value={{ localizer, accessors, getters, components: calendarComponents, rtl }}
    >
      <div
        className={cn(
          "flex flex-col h-full rounded-lg border border-border bg-background text-foreground overflow-hidden",
          rtl && "direction-rtl",
          className,
        )}
        style={style}
        {...elementProps}
      >
        {/* Toolbar */}
        {toolbar && (
          <div className="border-b border-border">
            {React.createElement(calendarComponents.toolbar ?? Toolbar, {
              date: currentDate,
              view: currentView,
              views: viewNames,
              label,
              localizer,
              onNavigate: handleNavigate,
              onView: handleViewChange,
              messages,
              onZoomIn,
              onZoomOut,
              canZoomIn,
              canZoomOut,
            })}
          </div>
        )}

        {/* View */}
        <div className="flex-1 min-h-0 overflow-hidden">
          <ViewComponent
            date={currentDate}
            events={events}
            backgroundEvents={backgroundEvents}
            getNow={getNow}
            selected={undefined}
            selectable={selectable}
            longPressThreshold={longPressThreshold}
            step={step}
            timeslots={timeslots}
            min={minDate}
            max={maxDate}
            scrollToTime={scrollToTime}
            length={length}
            popup={popup}
            popupOffset={popupOffset}
            accessors={accessors}
            getters={getters}
            localizer={localizer}
            components={calendarComponents}
            rtl={rtl}
            resources={resourceList}
            resourceAccessor={resourceAccessor}
            dayLayoutAlgorithm={dayLayoutAlgorithm}
            onSelectSlot={onSelectSlot}
            onSelect={onSelectEvent}
            onDoubleClick={handleDoubleClickEvent}
            onKeyPress={onKeyPressEvent}
            onShowMore={onShowMore}
            onDrillDown={handleDrillDown}
            onNavigate={handleNavigate}
            messages={messages}
          />
        </div>
      </div>
    </CalendarProvider>

    {/* ── Event Detail Sheet ── */}
    {sheetEvent && (() => {
      const SheetComp = calendarComponents.eventDetailSheet ?? EventDetailSheet
      const sheetEventStart = accessors.start(sheetEvent)
      const sheetEventEnd = accessors.end(sheetEvent)
      const sheetEventTitle = accessors.title(sheetEvent)
      const sheetEventAllDay = accessors.allDay(sheetEvent)
      return (
        <SheetComp
          event={sheetEvent}
          open={sheetOpen}
          onOpenChange={(open: boolean) => { if (!open) setSheetEvent(null) }}
          title={sheetEventTitle}
          start={sheetEventStart}
          end={sheetEventEnd}
          isAllDay={sheetEventAllDay}
          localizer={localizer}
          onSave={onEventSave ? handleSheetSave : undefined}
          onDelete={onEventDelete ? handleSheetDelete : undefined}
          side={eventDetailSide}
        >
          {eventDetailContent?.(sheetEvent)}
        </SheetComp>
      )
    })()}
    </DnDProvider>
  )
}

Calendar.displayName = "Calendar"

"use client"

import { createContext, useContext } from "react"
import type {
  Accessors,
  CalendarComponents,
  CalendarEvent,
  DateLocalizer,
  Getters,
} from "./types"

export interface CalendarContextValue<TEvent extends CalendarEvent = CalendarEvent> {
  localizer: DateLocalizer
  accessors: Accessors<TEvent>
  getters: Getters<TEvent>
  components: CalendarComponents<TEvent>
  rtl?: boolean
}

const CalendarContext = createContext<CalendarContextValue | null>(null)

export function CalendarProvider<TEvent extends CalendarEvent = CalendarEvent>({
  children,
  value,
}: {
  children: React.ReactNode
  value: CalendarContextValue<TEvent>
}) {
  return (
    <CalendarContext.Provider value={value as unknown as CalendarContextValue}>
      {children}
    </CalendarContext.Provider>
  )
}

export function useCalendarContext<
  TEvent extends CalendarEvent = CalendarEvent,
>(): CalendarContextValue<TEvent> {
  const ctx = useContext(CalendarContext)
  if (!ctx) {
    throw new Error("useCalendarContext must be used within a <CalendarProvider>")
  }
  return ctx as unknown as CalendarContextValue<TEvent>
}

export default CalendarContext

import type { ReactNode, CSSProperties, HTMLAttributes } from "react"

// ─── Navigation & Views ───────────────────────────────────────────────
export type NavigateAction = "PREV" | "NEXT" | "TODAY" | "DATE"

export type View = "month" | "week" | "work_week" | "day" | "agenda"

// ─── Event ────────────────────────────────────────────────────────────
export interface CalendarEvent {
  title?: string
  start?: Date
  end?: Date
  allDay?: boolean
  resource?: unknown
  [key: string]: unknown
}

// ─── Accessor ─────────────────────────────────────────────────────────
export type Accessor<TEvent, TValue> =
  | keyof TEvent
  | ((event: TEvent) => TValue)

// ─── Format ───────────────────────────────────────────────────────────
export type DateFormat = string | ((date: Date, culture?: string, localizer?: DateLocalizer) => string)

export type DateRangeFormat = (
  range: { start: Date; end: Date },
  culture?: string,
  localizer?: DateLocalizer,
) => string

// ─── Formats (all optional overrides) ─────────────────────────────────
export interface CalendarFormats {
  dateFormat?: DateFormat
  dayFormat?: DateFormat
  weekdayFormat?: DateFormat
  timeGutterFormat?: DateFormat
  monthHeaderFormat?: DateFormat
  dayRangeHeaderFormat?: DateRangeFormat
  dayHeaderFormat?: DateFormat
  agendaHeaderFormat?: DateRangeFormat
  selectRangeFormat?: DateRangeFormat
  eventTimeRangeFormat?: DateRangeFormat
  eventTimeRangeStartFormat?: DateRangeFormat
  eventTimeRangeEndFormat?: DateRangeFormat
  agendaDateFormat?: DateFormat
  agendaTimeFormat?: DateFormat
  agendaTimeRangeFormat?: DateRangeFormat
}

// ─── Messages (i18n) ──────────────────────────────────────────────────
export interface CalendarMessages {
  date?: string
  time?: string
  event?: string
  allDay?: string
  week?: string
  work_week?: string
  day?: string
  month?: string
  previous?: string
  next?: string
  yesterday?: string
  tomorrow?: string
  today?: string
  agenda?: string
  noEventsInRange?: string
  showMore?: (count: number) => string
}

// ─── Prop Getters ─────────────────────────────────────────────────────
export type EventPropGetter<TEvent = CalendarEvent> = (
  event: TEvent,
  start: Date,
  end: Date,
  isSelected: boolean,
) => { className?: string; style?: CSSProperties }

export type SlotPropGetter = (
  date: Date,
  resourceId?: string | number,
) => { className?: string; style?: CSSProperties }

export type DayPropGetter = (
  date: Date,
) => { className?: string; style?: CSSProperties }

// ─── Slot Info ────────────────────────────────────────────────────────
export interface SlotInfo {
  start: Date
  end: Date
  slots: Date[]
  action: "select" | "click" | "doubleClick"
  bounds?: { x: number; y: number; top: number; bottom: number; left: number; right: number }
  box?: { x: number; y: number; clientX: number; clientY: number }
  resourceId?: string | number
}

// ─── Components (overridable sub-components) ──────────────────────────
export interface CalendarComponents<TEvent = CalendarEvent> {
  event?: React.ComponentType<EventComponentProps<TEvent>>
  eventWrapper?: React.ComponentType<EventWrapperProps<TEvent>>
  eventContainerWrapper?: React.ComponentType<{ children: ReactNode }>
  dateCellWrapper?: React.ComponentType<{ children: ReactNode; value: Date; range: Date[] }>
  dayWrapper?: React.ComponentType<{ children: ReactNode }>
  timeSlotWrapper?: React.ComponentType<{ children: ReactNode; value: Date; resource?: unknown }>
  timeGutterWrapper?: React.ComponentType<{ children: ReactNode }>
  timeGutterHeader?: React.ComponentType<Record<string, never>>
  toolbar?: React.ComponentType<ToolbarProps>
  agenda?: {
    date?: React.ComponentType<{ day: Date; label: string }>
    time?: React.ComponentType<{ event: TEvent; day: Date; label: string }>
    event?: React.ComponentType<{ event: TEvent; title: string }>
  }
  day?: {
    header?: React.ComponentType<{ date: Date; label: string }>
    event?: React.ComponentType<EventComponentProps<TEvent>>
  }
  week?: {
    header?: React.ComponentType<{ date: Date; label: string }>
    event?: React.ComponentType<EventComponentProps<TEvent>>
  }
  month?: {
    header?: React.ComponentType<{ date: Date; label: string }>
    dateHeader?: React.ComponentType<DateHeaderProps>
    event?: React.ComponentType<EventComponentProps<TEvent>>
  }
  resourceHeader?: React.ComponentType<ResourceHeaderProps>
  header?: React.ComponentType<{ date: Date; label: string; localizer: DateLocalizer }>
  /** Custom event detail sheet (opened on double-click). Receives the event and open/close state. */
  eventDetailSheet?: React.ComponentType<EventDetailSheetProps<TEvent>>
}

// ─── Sub-component Props ──────────────────────────────────────────────
export interface EventComponentProps<TEvent = CalendarEvent> {
  event: TEvent
  title: string
  isAllDay?: boolean
  localizer: DateLocalizer
  slotStart?: Date
  slotEnd?: Date
  continuesPrior?: boolean
  continuesAfter?: boolean
}

// ─── Event Detail Sheet Props ─────────────────────────────────────────
export interface EventDetailSheetProps<TEvent = CalendarEvent> {
  /** The event to display/edit */
  event: TEvent
  /** Whether the sheet is open */
  open: boolean
  /** Called when the sheet should close */
  onOpenChange: (open: boolean) => void
  /** Event title (resolved from accessor) */
  title: string
  /** Event start date */
  start: Date
  /** Event end date */
  end: Date
  /** Whether the event is all-day */
  isAllDay: boolean
  /** The localizer for formatting dates/times */
  localizer: DateLocalizer
  /** Called when the user saves edits to the event. Receives the updated event and the original event. */
  onSave?: (updatedEvent: TEvent, originalEvent: TEvent) => void
  /** Called when the user deletes the event */
  onDelete?: (event: TEvent) => void
  /** Side the sheet slides in from */
  side?: "top" | "right" | "bottom" | "left"
  /** Additional custom content rendered inside the sheet body */
  children?: ReactNode
}

export interface EventWrapperProps<TEvent = CalendarEvent> {
  event: TEvent
  children: ReactNode
  continuesPrior?: boolean
  continuesAfter?: boolean
  isAllDay?: boolean
  selected?: boolean
  label?: string
  onSelect?: (event: TEvent, e: React.SyntheticEvent) => void
  onDoubleClick?: (event: TEvent, e: React.SyntheticEvent) => void
}

export interface DateHeaderProps {
  date: Date
  label: string
  drilldownView?: View
  isOffRange?: boolean
  onDrillDown?: (date: Date, view: View) => void
}

export interface ResourceHeaderProps {
  label: ReactNode
  index: number
  resource: Resource
}

export interface ToolbarProps {
  date: Date
  view: View
  views: View[]
  label: string
  localizer: DateLocalizer
  onNavigate: (action: NavigateAction) => void
  onView: (view: View) => void
  messages?: Partial<CalendarMessages>
  children?: ReactNode
  /** Zoom in (decrease step) */
  onZoomIn?: () => void
  /** Zoom out (increase step) */
  onZoomOut?: () => void
  /** Whether zoom-in is allowed */
  canZoomIn?: boolean
  /** Whether zoom-out is allowed */
  canZoomOut?: boolean
}

// ─── Resource ─────────────────────────────────────────────────────────
export interface Resource {
  id: string | number
  title: string
  [key: string]: unknown
}

// ─── Localizer ────────────────────────────────────────────────────────
export interface DateLocalizer {
  formats: CalendarFormats
  messages: Required<CalendarMessages>

  format(value: Date, formatStr: DateFormat, culture?: string): string
  format(value: { start: Date; end: Date }, formatStr: string, culture?: string): string
  parse?(value: string, format: string, culture?: string): Date

  startOfWeek(culture?: string): number
  merge(date: Date, time: Date): Date
  inRange(day: Date, min: Date, max: Date, unit?: string): boolean
  lt(a: Date, b: Date, unit?: string): boolean
  lte(a: Date, b: Date, unit?: string): boolean
  gt(a: Date, b: Date, unit?: string): boolean
  gte(a: Date, b: Date, unit?: string): boolean
  eq(a: Date, b: Date, unit?: string): boolean
  neq(a: Date, b: Date, unit?: string): boolean
  add(date: Date, amount: number, unit: string): Date
  startOf(date: Date, unit: string): Date
  endOf(date: Date, unit: string): Date
  range(start: Date, end: Date, unit?: string): Date[]
  diff(a: Date, b: Date, unit?: string): number
  ceil(date: Date, unit: string): Date
  min(a: Date, b: Date): Date
  max(a: Date, b: Date): Date
  minutes(date: Date): number

  firstVisibleDay(date: Date, localizer?: DateLocalizer): Date
  lastVisibleDay(date: Date, localizer?: DateLocalizer): Date
  visibleDays(date: Date, localizer?: DateLocalizer): Date[]

  getSlotDate(date: Date, minutesFromMidnight: number, offset: number): Date
  getTimezoneOffset(date: Date): number
  getDstOffset(start: Date, end: Date): number
  getTotalMin(start: Date, end: Date): number
  getMinutesFromMidnight(date: Date): number

  continuesPrior(start: Date, first: Date): boolean
  continuesAfter(start: Date, end: Date, last: Date): boolean

  sortEvents(eventA: CalendarEvent, eventB: CalendarEvent, accessors: Accessors): number
  inEventRange(event: CalendarEvent, range: { start: Date; end: Date }, accessors: Accessors): boolean
  isSameDate(a: Date, b: Date, unit?: string): boolean
  startAndEndAreDateOnly(start: Date, end: Date): boolean

  segmentOffset?: number
}

// ─── Accessors (resolved functions) ───────────────────────────────────
export interface Accessors<TEvent = CalendarEvent> {
  start: (event: TEvent) => Date
  end: (event: TEvent) => Date
  title: (event: TEvent) => string
  tooltip: (event: TEvent) => string
  allDay: (event: TEvent) => boolean
  resource?: (event: TEvent) => unknown
  resourceId?: (event: TEvent) => string | number
  eventId?: (event: TEvent) => string | number
}

// ─── Getters ──────────────────────────────────────────────────────────
export interface Getters<TEvent = CalendarEvent> {
  eventProp: (event: TEvent, start: Date, end: Date, isSelected: boolean) => { className?: string; style?: CSSProperties }
  slotProp: (date: Date, resourceId?: string | number) => { className?: string; style?: CSSProperties }
  dayProp: (date: Date) => { className?: string; style?: CSSProperties }
  slotGroupProp: () => { className?: string; style?: CSSProperties }
}

