// ─── Accessor resolution ──────────────────────────────────────────────
export function accessor<TEvent, TValue>(
  data: TEvent,
  field: Accessor<TEvent, TValue>,
): TValue {
  if (typeof field === "function") {
    return (field as (event: TEvent) => TValue)(data)
  }
  if (typeof field === "string" && data != null && typeof data === "object") {
    return (data as Record<string, unknown>)[field] as TValue
  }
  return data as unknown as TValue
}

export function wrapAccessor<TEvent, TValue>(
  acc: Accessor<TEvent, TValue>,
): (data: TEvent) => TValue {
  return (data: TEvent) => accessor(data, acc)
}

// ─── Notify ───────────────────────────────────────────────────────────
export function notify<T extends unknown[]>(
  handler: ((...args: T) => void) | undefined,
  args: T,
): void {
  handler?.(...args)
}

// ─── Unique ID ────────────────────────────────────────────────────────
let idCounter = 0
export function uniqueId(prefix = ""): string {
  return `${prefix}${++idCounter}`
}

// ─── Default Messages ─────────────────────────────────────────────────
const defaultMessages: Required<CalendarMessages> = {
  date: "Date",
  time: "Time",
  event: "Event",
  allDay: "All Day",
  week: "Week",
  work_week: "Work Week",
  day: "Day",
  month: "Month",
  previous: "Back",
  next: "Next",
  yesterday: "Yesterday",
  tomorrow: "Tomorrow",
  today: "Today",
  agenda: "Agenda",
  noEventsInRange: "There are no events in this range.",
  showMore: (count: number) => `+${count} more`,
}

export function mergeMessages(
  base?: Record<string, unknown>,
  custom?: Partial<CalendarMessages>,
): Required<CalendarMessages> {
  return { ...defaultMessages, ...base, ...custom } as Required<CalendarMessages>
}

// ─── Event selection check ────────────────────────────────────────────
export function isSelected<TEvent extends CalendarEvent>(
  event: TEvent,
  selected?: TEvent,
): boolean {
  if (!selected) return false
  return event === selected
}

// ─── Chunk array ──────────────────────────────────────────────────────
export function chunk<T>(arr: T[], size: number): T[][] {
  const result: T[][] = []
  for (let i = 0; i < arr.length; i += size) {
    result.push(arr.slice(i, i + size))
  }
  return result
}

// ─── Noop wrapper ─────────────────────────────────────────────────────
export function NoopWrapper({ children }: { children: ReactNode }): ReactNode {
  return children
}

/**
 * DateLocalizer — the core abstraction for formatting and date arithmetic.
 *
 * Each localizer adapter (date-fns, dayjs, luxon, moment) creates an
 * instance of this class with its own `format` and `firstOfWeek` implementations.
 * All date math falls back to our pure-TS `dates` utilities by default.
 */

import type {
  CalendarEvent,
  CalendarFormats,
  CalendarMessages,
  Accessors,
  DateLocalizer as IDateLocalizer,
} from "./types"
import * as dates from "./lib/dates"
import { mergeMessages } from "./helpers"

export interface LocalizerSpec {
  formats: CalendarFormats
  firstOfWeek: (culture?: string) => number
  format: (value: Date, formatStr: string, culture?: string) => string
  parse?: (value: string, format: string, culture?: string) => Date

  // Optional overrides — all default to our pure TS date math
  merge?: (date: Date, time: Date) => Date
  inRange?: (day: Date, min: Date, max: Date, unit?: string) => boolean
  lt?: (a: Date, b: Date, unit?: string) => boolean
  lte?: (a: Date, b: Date, unit?: string) => boolean
  gt?: (a: Date, b: Date, unit?: string) => boolean
  gte?: (a: Date, b: Date, unit?: string) => boolean
  eq?: (a: Date, b: Date, unit?: string) => boolean
  neq?: (a: Date, b: Date, unit?: string) => boolean
  startOf?: (date: Date, unit: string) => Date
  endOf?: (date: Date, unit: string) => Date
  add?: (date: Date, amount: number, unit: string) => Date
  range?: (start: Date, end: Date, unit?: string) => Date[]
  diff?: (a: Date, b: Date, unit?: string) => number
  ceil?: (date: Date, unit: string) => Date
  min?: (a: Date, b: Date) => Date
  max?: (a: Date, b: Date) => Date
  minutes?: (date: Date) => number
  firstVisibleDay?: (date: Date, localizer?: IDateLocalizer) => Date
  lastVisibleDay?: (date: Date, localizer?: IDateLocalizer) => Date
  visibleDays?: (date: Date, localizer?: IDateLocalizer) => Date[]
  getSlotDate?: (dt: Date, minutesFromMidnight: number, offset: number) => Date
  getTimezoneOffset?: (date: Date) => number
  getDstOffset?: (start: Date, end: Date) => number
  getTotalMin?: (start: Date, end: Date) => number
  getMinutesFromMidnight?: (date: Date) => number
  continuesPrior?: (start: Date, first: Date) => boolean
  continuesAfter?: (start: Date, end: Date, last: Date) => boolean
  sortEvents?: (args: { evtA: SortableEvent; evtB: SortableEvent }) => number
  inEventRange?: (args: { event: { start: Date; end: Date }; range: { start: Date; end: Date } }) => boolean
  isSameDate?: (a: Date, b: Date, unit?: string) => boolean
  startAndEndAreDateOnly?: (start: Date, end: Date) => boolean
  daySpan?: (start: Date, end: Date) => number
  browserTZOffset?: () => number
}

interface SortableEvent {
  start: Date
  end: Date
  allDay: boolean
}

// ─── Default implementations ──────────────────────────────────────────

function defaultGetSlotDate(dt: Date, minutesFromMidnight: number, offset: number): Date {
  return new Date(dt.getFullYear(), dt.getMonth(), dt.getDate(), 0, minutesFromMidnight + offset, 0, 0)
}

function defaultGetDstOffset(start: Date, end: Date): number {
  return start.getTimezoneOffset() - end.getTimezoneOffset()
}

function defaultGetTotalMin(start: Date, end: Date): number {
  return dates.diff(start, end, "minutes") + defaultGetDstOffset(start, end)
}

function defaultGetMinutesFromMidnight(start: Date): number {
  const dayStart = dates.startOf(start, "day")
  return dates.diff(dayStart, start, "minutes") + defaultGetDstOffset(dayStart, start)
}

function defaultContinuesPrior(start: Date, first: Date): boolean {
  return dates.lt(start, first, "day")
}

function defaultContinuesAfter(start: Date, end: Date, last: Date): boolean {
  const sameMin = dates.eq(start, end, "minutes")
  return sameMin ? dates.gte(end, last, "minutes") : dates.gt(end, last, "minutes")
}

function defaultDaySpan(start: Date, end: Date): number {
  return dates.duration(start, end, "day")
}

function defaultSortEvents({ evtA, evtB }: { evtA: SortableEvent; evtB: SortableEvent }): number {
  const startSort = +dates.startOf(evtA.start, "day") - +dates.startOf(evtB.start, "day")
  const durA = defaultDaySpan(evtA.start, evtA.end)
  const durB = defaultDaySpan(evtB.start, evtB.end)
  return (
    startSort ||
    durB - durA ||
    (evtB.allDay ? 1 : 0) - (evtA.allDay ? 1 : 0) ||
    +evtA.start - +evtB.start ||
    +evtA.end - +evtB.end
  )
}

function defaultInEventRange({
  event,
  range,
}: {
  event: { start: Date; end: Date }
  range: { start: Date; end: Date }
}): boolean {
  const eStart = dates.startOf(event.start, "day")
  const startsBeforeEnd = dates.lte(eStart, range.end, "day")
  const sameMin = dates.neq(eStart, event.end, "minutes")
  const endsAfterStart = sameMin
    ? dates.gt(event.end, range.start, "minutes")
    : dates.gte(event.end, range.start, "minutes")
  return startsBeforeEnd && endsAfterStart
}

// ─── DateLocalizer class ──────────────────────────────────────────────

export class DateLocalizer implements IDateLocalizer {
  formats: CalendarFormats
  messages: Required<CalendarMessages>
  segmentOffset: number

  private _format: (value: Date, formatStr: string, culture?: string) => string
  private _firstOfWeek: (culture?: string) => number

  // Date arithmetic (all overridable)
  merge: (date: Date, time: Date) => Date
  inRange: (day: Date, min: Date, max: Date, unit?: string) => boolean
  lt: (a: Date, b: Date, unit?: string) => boolean
  lte: (a: Date, b: Date, unit?: string) => boolean
  gt: (a: Date, b: Date, unit?: string) => boolean
  gte: (a: Date, b: Date, unit?: string) => boolean
  eq: (a: Date, b: Date, unit?: string) => boolean
  neq: (a: Date, b: Date, unit?: string) => boolean
  startOf: (date: Date, unit: string) => Date
  endOf: (date: Date, unit: string) => Date
  add: (date: Date, amount: number, unit: string) => Date
  range: (start: Date, end: Date, unit?: string) => Date[]
  diff: (a: Date, b: Date, unit?: string) => number
  ceil: (date: Date, unit: string) => Date
  min: (a: Date, b: Date) => Date
  max: (a: Date, b: Date) => Date
  minutes: (date: Date) => number

  // Visibility
  firstVisibleDay: (date: Date, localizer?: IDateLocalizer) => Date
  lastVisibleDay: (date: Date, localizer?: IDateLocalizer) => Date
  visibleDays: (date: Date, localizer?: IDateLocalizer) => Date[]

  // Time slots
  getSlotDate: (dt: Date, minutesFromMidnight: number, offset: number) => Date
  getTimezoneOffset: (date: Date) => number
  getDstOffset: (start: Date, end: Date) => number
  getTotalMin: (start: Date, end: Date) => number
  getMinutesFromMidnight: (date: Date) => number

  // Event helpers
  continuesPrior: (start: Date, first: Date) => boolean
  continuesAfter: (start: Date, end: Date, last: Date) => boolean
  sortEvents: (eventA: CalendarEvent, eventB: CalendarEvent, accessors: Accessors) => number
  inEventRange: (event: CalendarEvent, range: { start: Date; end: Date }, accessors: Accessors) => boolean
  isSameDate: (a: Date, b: Date, unit?: string) => boolean
  startAndEndAreDateOnly: (start: Date, end: Date) => boolean

  parse?: (value: string, format: string, culture?: string) => Date

  constructor(spec: LocalizerSpec) {
    this.formats = spec.formats
    this.messages = mergeMessages()
    this._format = spec.format
    this._firstOfWeek = spec.firstOfWeek
    this.parse = spec.parse

    // Date math with defaults
    this.merge = spec.merge ?? ((d, t) => dates.merge(d, t)!)
    this.inRange = spec.inRange ?? dates.inRange
    this.lt = spec.lt ?? dates.lt
    this.lte = spec.lte ?? dates.lte
    this.gt = spec.gt ?? dates.gt
    this.gte = spec.gte ?? dates.gte
    this.eq = spec.eq ?? dates.eq
    this.neq = spec.neq ?? dates.neq
    this.startOf = spec.startOf ?? dates.startOf
    this.endOf = spec.endOf ?? dates.endOf
    this.add = spec.add ?? dates.add
    this.range = spec.range ?? dates.range
    this.diff = spec.diff ?? dates.diff
    this.ceil = spec.ceil ?? dates.ceil
    this.min = spec.min ?? dates.min
    this.max = spec.max ?? dates.max
    this.minutes = spec.minutes ?? dates.minutes

    // Visibility
    const sow = () => this.startOfWeek()
    this.firstVisibleDay = spec.firstVisibleDay ?? (((d: Date) => dates.firstVisibleDay(d, sow())) as (date: Date, localizer?: IDateLocalizer) => Date)
    this.lastVisibleDay = spec.lastVisibleDay ?? (((d: Date) => dates.lastVisibleDay(d, sow())) as (date: Date, localizer?: IDateLocalizer) => Date)
    this.visibleDays = spec.visibleDays ?? (((d: Date) => dates.visibleDays(d, sow())) as (date: Date, localizer?: IDateLocalizer) => Date[])

    // Time slots
    this.getSlotDate = spec.getSlotDate ?? defaultGetSlotDate
    this.getTimezoneOffset = spec.getTimezoneOffset ?? ((v) => v.getTimezoneOffset())
    this.getDstOffset = spec.getDstOffset ?? defaultGetDstOffset
    this.getTotalMin = spec.getTotalMin ?? defaultGetTotalMin
    this.getMinutesFromMidnight = spec.getMinutesFromMidnight ?? defaultGetMinutesFromMidnight

    // Event helpers
    this.continuesPrior = spec.continuesPrior ?? defaultContinuesPrior
    this.continuesAfter = spec.continuesAfter ?? defaultContinuesAfter
    this.isSameDate = spec.isSameDate ?? ((a, b, unit?) => dates.eq(a, b, unit ?? "day"))
    this.startAndEndAreDateOnly = spec.startAndEndAreDateOnly ?? ((s, e) => dates.isJustDate(s) && dates.isJustDate(e))

    // These need accessors, so we wrap
    const sortFn = spec.sortEvents ?? defaultSortEvents
    this.sortEvents = (_eventA, _eventB, accessors) => {
      const evtA = { start: accessors.start(_eventA), end: accessors.end(_eventA), allDay: accessors.allDay(_eventA) }
      const evtB = { start: accessors.start(_eventB), end: accessors.end(_eventB), allDay: accessors.allDay(_eventB) }
      return sortFn({ evtA, evtB })
    }

    const inRangeFn = spec.inEventRange ?? defaultInEventRange
    this.inEventRange = (event, range, accessors) => {
      return inRangeFn({ event: { start: accessors.start(event), end: accessors.end(event) }, range })
    }

    this.segmentOffset = spec.browserTZOffset ? spec.browserTZOffset() : 0
  }

  format(value: Date | { start: Date; end: Date }, formatStr: string | ((date: Date, culture?: string, localizer?: IDateLocalizer) => string), culture?: string): string {
    if (typeof formatStr === "function") {
      if (typeof (value as any).start !== "undefined") {
        return formatStr((value as { start: Date }).start, culture, this)
      }
      return formatStr(value as Date, culture, this)
    }
    // Resolve format name from the formats map (e.g. "monthHeaderFormat" → "MMMM yyyy")
    const resolvedFormat = (this.formats as Record<string, unknown>)[formatStr] ?? formatStr
    // If resolved to a range format function
    if (typeof resolvedFormat === "function") {
      if (typeof (value as any).start !== "undefined") {
        return (resolvedFormat as (range: { start: Date; end: Date }, culture?: string, localizer?: IDateLocalizer) => string)(
          value as { start: Date; end: Date },
          culture,
          this,
        )
      }
      return (resolvedFormat as (date: Date, culture?: string, localizer?: IDateLocalizer) => string)(
        value as Date,
        culture,
        this,
      )
    }
    // Resolved to a string format — use it instead of the original key
    const actualFormat = typeof resolvedFormat === "string" ? resolvedFormat : formatStr
    if (typeof (value as any).start !== "undefined") {
      return this._format((value as { start: Date }).start, actualFormat, culture)
    }
    return this._format(value as Date, actualFormat, culture)
  }

  startOfWeek(culture?: string): number {
    return this._firstOfWeek(culture)
  }
}

// ─── Merge localizer with user overrides ──────────────────────────────

export function mergeWithDefaults(
  localizer: DateLocalizer,
  culture: string | undefined,
  formatOverrides: Partial<CalendarFormats> | undefined,
  messages: Partial<CalendarMessages> | undefined,
): DateLocalizer & { messages: Required<CalendarMessages> } {
  const mergedFormats = { ...localizer.formats, ...formatOverrides }
  const mergedMessages = mergeMessages(messages)

  // Return a proxy-like object that delegates to the localizer
  // but overrides format and startOfWeek with culture baked in
  return Object.create(localizer, {
    messages: { value: mergedMessages, writable: false },
    startOfWeek: { value: () => localizer.startOfWeek(culture), writable: false },
    format: {
      value: (value: Date, format: string) => {
        const resolved = (mergedFormats as Record<string, unknown>)[format] ?? format
        return localizer.format(value, resolved as string, culture)
      },
      writable: false,
    },
  })
}

/**
 * Date arithmetic utilities for the calendar.
 * Pure TypeScript — no external date-arithmetic dependency.
 * All operations use native Date and are timezone-aware.
 */

const MILLI = {
  seconds: 1000,
  minutes: 1000 * 60,
  hours: 1000 * 60 * 60,
  day: 1000 * 60 * 60 * 24,
} as const

// ─── Start/End of unit ────────────────────────────────────────────────
export function startOf(date: Date, unit: string, firstOfWeek?: number): Date {
  const d = new Date(date)
  switch (unit) {
    case "year":
      d.setMonth(0, 1)
      d.setHours(0, 0, 0, 0)
      return d
    case "month":
      d.setDate(1)
      d.setHours(0, 0, 0, 0)
      return d
    case "week": {
      const day = d.getDay()
      const fow = firstOfWeek ?? 0
      const diff = (day - fow + 7) % 7
      d.setDate(d.getDate() - diff)
      d.setHours(0, 0, 0, 0)
      return d
    }
    case "day":
    case "date":
      d.setHours(0, 0, 0, 0)
      return d
    case "hours":
      d.setMinutes(0, 0, 0)
      return d
    case "minutes":
      d.setSeconds(0, 0)
      return d
    case "seconds":
      d.setMilliseconds(0)
      return d
    default:
      return d
  }
}

export function endOf(date: Date, unit: string, firstOfWeek?: number): Date {
  const d = new Date(date)
  switch (unit) {
    case "year":
      d.setMonth(11, 31)
      d.setHours(23, 59, 59, 999)
      return d
    case "month":
      d.setMonth(d.getMonth() + 1, 0)
      d.setHours(23, 59, 59, 999)
      return d
    case "week": {
      const s = startOf(d, "week", firstOfWeek)
      s.setDate(s.getDate() + 6)
      s.setHours(23, 59, 59, 999)
      return s
    }
    case "day":
    case "date":
      d.setHours(23, 59, 59, 999)
      return d
    case "hours":
      d.setMinutes(59, 59, 999)
      return d
    case "minutes":
      d.setSeconds(59, 999)
      return d
    case "seconds":
      d.setMilliseconds(999)
      return d
    default:
      return d
  }
}

// ─── Add ──────────────────────────────────────────────────────────────
export function add(date: Date, amount: number, unit: string): Date {
  const d = new Date(date)
  switch (unit) {
    case "year":
      d.setFullYear(d.getFullYear() + amount)
      return d
    case "month":
      d.setMonth(d.getMonth() + amount)
      return d
    case "week":
      d.setDate(d.getDate() + 7 * amount)
      return d
    case "day":
    case "date":
      d.setDate(d.getDate() + amount)
      return d
    case "hours":
      d.setHours(d.getHours() + amount)
      return d
    case "minutes":
      d.setMinutes(d.getMinutes() + amount)
      return d
    case "seconds":
      d.setSeconds(d.getSeconds() + amount)
      return d
    case "milliseconds":
      d.setMilliseconds(d.getMilliseconds() + amount)
      return d
    default:
      return d
  }
}

// ─── Comparison ───────────────────────────────────────────────────────
export function eq(a: Date, b: Date, unit?: string): boolean {
  if (!unit) return +a === +b
  return +startOf(a, unit) === +startOf(b, unit)
}

export function neq(a: Date, b: Date, unit?: string): boolean {
  return !eq(a, b, unit)
}

export function gt(a: Date, b: Date, unit?: string): boolean {
  if (!unit) return +a > +b
  return +startOf(a, unit) > +startOf(b, unit)
}

export function gte(a: Date, b: Date, unit?: string): boolean {
  if (!unit) return +a >= +b
  return +startOf(a, unit) >= +startOf(b, unit)
}

export function lt(a: Date, b: Date, unit?: string): boolean {
  if (!unit) return +a < +b
  return +startOf(a, unit) < +startOf(b, unit)
}

export function lte(a: Date, b: Date, unit?: string): boolean {
  if (!unit) return +a <= +b
  return +startOf(a, unit) <= +startOf(b, unit)
}

export function inRange(day: Date, min: Date, max: Date, unit?: string): boolean {
  return gte(day, min, unit) && lte(day, max, unit)
}

export function min(a: Date, b: Date): Date {
  return +a < +b ? a : b
}

export function max(a: Date, b: Date): Date {
  return +a > +b ? a : b
}

// ─── Diff / Duration ──────────────────────────────────────────────────
export function diff(dateA: Date, dateB: Date, unit?: string): number {
  if (!unit || unit === "milliseconds") return Math.abs(+dateA - +dateB)
  const key = unit === "date" ? "day" : unit
  if (key in MILLI) {
    return Math.round(
      Math.abs(+startOf(dateA, unit) / MILLI[key as keyof typeof MILLI] - +startOf(dateB, unit) / MILLI[key as keyof typeof MILLI])
    )
  }
  if (unit === "month") {
    return Math.abs(
      (dateA.getFullYear() - dateB.getFullYear()) * 12 + dateA.getMonth() - dateB.getMonth()
    )
  }
  if (unit === "year") {
    return Math.abs(dateA.getFullYear() - dateB.getFullYear())
  }
  return Math.abs(+dateA - +dateB)
}

export function duration(start: Date, end: Date, unit: string): number {
  if (unit === "day") {
    return Math.abs(
      Math.round((+startOf(end, "day") - +startOf(start, "day")) / MILLI.day)
    )
  }
  return diff(start, end, unit)
}

// ─── Ceil ─────────────────────────────────────────────────────────────
export function ceil(date: Date, unit: string): Date {
  const floor = startOf(date, unit)
  return eq(floor, date) ? floor : add(floor, 1, unit)
}

// ─── Range ────────────────────────────────────────────────────────────
export function range(start: Date, end: Date, unit: string = "day"): Date[] {
  let current = new Date(start)
  const result: Date[] = []
  while (lte(current, end, unit)) {
    result.push(new Date(current))
    current = add(current, 1, unit)
  }
  return result
}

// ─── Merge (date part + time part) ────────────────────────────────────
export function merge(date: Date | null, time: Date | null): Date | null {
  if (time == null && date == null) return null
  const t = time ?? new Date()
  const d = date ?? new Date()
  const result = startOf(d, "day")
  result.setHours(t.getHours(), t.getMinutes(), t.getSeconds(), t.getMilliseconds())
  return result
}

// ─── Getters ──────────────────────────────────────────────────────────
export function minutes(date: Date): number {
  return date.getMinutes()
}

export function hours(date: Date): number {
  return date.getHours()
}

// ─── Visibility helpers ───────────────────────────────────────────────
export function firstVisibleDay(date: Date, startOfWeekDay: number): Date {
  const firstOfMonth = startOf(date, "month")
  return startOf(firstOfMonth, "week", startOfWeekDay)
}

export function lastVisibleDay(date: Date, startOfWeekDay: number): Date {
  const endOfMonth = endOf(date, "month")
  return endOf(endOfMonth, "week", startOfWeekDay)
}

export function visibleDays(date: Date, startOfWeekDay: number): Date[] {
  const first = firstVisibleDay(date, startOfWeekDay)
  const last = lastVisibleDay(date, startOfWeekDay)
  return range(first, last, "day")
}

// ─── Zero-time checks ────────────────────────────────────────────────
export function isJustDate(date: Date): boolean {
  return (
    date.getHours() === 0 &&
    date.getMinutes() === 0 &&
    date.getSeconds() === 0 &&
    date.getMilliseconds() === 0
  )
}

export function eqTime(a: Date, b: Date): boolean {
  return a.getHours() === b.getHours() && a.getMinutes() === b.getMinutes() && a.getSeconds() === b.getSeconds()
}

// ─── Today helpers ────────────────────────────────────────────────────
export function today(): Date {
  return startOf(new Date(), "day")
}

export function tomorrow(): Date {
  return add(today(), 1, "day")
}

export function yesterday(): Date {
  return add(today(), -1, "day")
}

/**
 * Event segment & level calculation for month/all-day row layout.
 */

import type {
  CalendarEvent,
  Accessors,
  DateLocalizer,
  EventSegment,
} from "../types"

export function endOfRange({
  dateRange,
  unit = "day",
  localizer,
}: {
  dateRange: Date[]
  unit?: string
  localizer: DateLocalizer
}): { first: Date; last: Date } {
  return {
    first: dateRange[0],
    last: localizer.add(dateRange[dateRange.length - 1], 1, unit),
  }
}

export function eventSegments<TEvent extends CalendarEvent>(
  event: TEvent,
  range: Date[],
  accessors: Accessors<TEvent>,
  localizer: DateLocalizer,
): EventSegment<TEvent> {
  const { first, last } = endOfRange({ dateRange: range, localizer })

  const slots = localizer.diff(first, last, "day")
  const start = localizer.max(
    localizer.startOf(accessors.start(event), "day"),
    first,
  )
  const end = localizer.min(localizer.ceil(accessors.end(event), "day"), last)

  const padding = range.findIndex((x) => localizer.isSameDate(x, start))
  let span = localizer.diff(start, end, "day")

  span = Math.min(span, slots)
  span = Math.max(span - (localizer.segmentOffset ?? 0), 1)

  return {
    event,
    span,
    left: padding + 1,
    right: Math.max(padding + span, 1),
  }
}

export function eventLevels<TEvent extends CalendarEvent>(
  rowSegments: EventSegment<TEvent>[],
  limit: number = Infinity,
): { levels: EventSegment<TEvent>[][]; extra: EventSegment<TEvent>[] } {
  const levels: EventSegment<TEvent>[][] = []
  const extra: EventSegment<TEvent>[] = []

  for (const seg of rowSegments) {
    let j = 0
    for (; j < levels.length; j++) {
      if (!segsOverlap(seg, levels[j])) break
    }

    if (j >= limit) {
      extra.push(seg)
    } else {
      ;(levels[j] || (levels[j] = [])).push(seg)
    }
  }

  for (const level of levels) {
    level.sort((a, b) => a.left - b.left)
  }

  return { levels, extra }
}

export function inRange<TEvent extends CalendarEvent>(
  e: TEvent,
  start: Date,
  end: Date,
  accessors: Accessors<TEvent>,
  localizer: DateLocalizer,
): boolean {
  const event = {
    start: accessors.start(e),
    end: accessors.end(e),
  }
  return localizer.inEventRange(e as CalendarEvent, { start, end }, accessors as Accessors<CalendarEvent>)
}

export function segsOverlap<TEvent extends CalendarEvent>(
  seg: EventSegment<TEvent>,
  otherSegs: EventSegment<TEvent>[],
): boolean {
  return otherSegs.some(
    (otherSeg) => otherSeg.left <= seg.right && otherSeg.right >= seg.left,
  )
}

export function sortWeekEvents<TEvent extends CalendarEvent>(
  events: TEvent[],
  accessors: Accessors<TEvent>,
  localizer: DateLocalizer,
): TEvent[] {
  const multiDayEvents: TEvent[] = []
  const standardEvents: TEvent[] = []

  for (const event of events) {
    const start = accessors.start(event)
    const end = accessors.end(event)
    const daySpan = Math.abs(
      Math.round(
        (+localizer.startOf(end, "day") - +localizer.startOf(start, "day")) / (1000 * 60 * 60 * 24),
      ),
    )
    if (daySpan > 1) {
      multiDayEvents.push(event)
    } else {
      standardEvents.push(event)
    }
  }

  const sorter = (a: TEvent, b: TEvent) => localizer.sortEvents(a as CalendarEvent, b as CalendarEvent, accessors as Accessors<CalendarEvent>)
  return [...multiDayEvents.sort(sorter), ...standardEvents.sort(sorter)]
}

export function sortEvents<TEvent extends CalendarEvent>(
  eventA: TEvent,
  eventB: TEvent,
  accessors: Accessors<TEvent>,
  localizer: DateLocalizer,
): number {
  return localizer.sortEvents(eventA as CalendarEvent, eventB as CalendarEvent, accessors as Accessors<CalendarEvent>)
}

/**
 * DateSlotMetrics — computes layout metrics for month/all-day row segments.
 */

import type {
  CalendarEvent,
  Accessors,
  DateLocalizer,
  EventSegment,
  DateSlotMetrics as IDateSlotMetrics,
} from "../types"
import { eventSegments, endOfRange, eventLevels } from "./event-levels"

function isSegmentInSlot<TEvent extends CalendarEvent>(
  seg: EventSegment<TEvent>,
  slot: number,
): boolean {
  return seg.left <= slot && seg.right >= slot
}

export interface DateSlotMetricsOptions<TEvent extends CalendarEvent = CalendarEvent> {
  range: Date[]
  events: TEvent[]
  maxRows: number
  minRows: number
  accessors: Accessors<TEvent>
  localizer: DateLocalizer
}

export function getDateSlotMetrics<TEvent extends CalendarEvent = CalendarEvent>(
  options: DateSlotMetricsOptions<TEvent>,
): IDateSlotMetrics<TEvent> {
  const { range, events, maxRows, minRows, accessors, localizer } = options
  const { first, last } = endOfRange({ dateRange: range, localizer })

  const segments = events.map((evt) =>
    eventSegments(evt, range, accessors, localizer),
  )

  const { levels, extra } = eventLevels(segments, Math.max(maxRows - 1, 1))

  // Pad levels up to minRows (subtract 1 for showMore button row when extra exists)
  const minEventRows = extra.length > 0 ? minRows - 1 : minRows
  while (levels.length < minEventRows) levels.push([])

  return {
    first,
    last,
    levels,
    extra,
    range,
    slots: range.length,

    clone(args) {
      return getDateSlotMetrics({ ...options, ...args })
    },

    getDateForSlot(slotNumber: number) {
      return range[slotNumber]
    },

    getSlotForDate(date: Date) {
      return range.findIndex((r) => localizer.isSameDate(r, date))
    },

    getEventsForSlot(slot: number) {
      return segments
        .filter((seg) => isSegmentInSlot(seg, slot))
        .map((seg) => seg.event)
    },

    continuesPrior(event: TEvent) {
      return localizer.continuesPrior(accessors.start(event), first)
    },

    continuesAfter(event: TEvent) {
      const start = accessors.start(event)
      const end = accessors.end(event)
      return localizer.continuesAfter(start, end, last)
    },
  }
}

/**
 * TimeSlotMetrics — computes slot positions for time-based views (day/week).
 */

import type { DateLocalizer } from "../types"

export interface TimeSlotMetricsOptions {
  min: Date
  max: Date
  step: number
  timeslots: number
  localizer: DateLocalizer
}

export interface ITimeSlotMetrics {
  groups: Date[][]
  update(args: TimeSlotMetricsOptions): ITimeSlotMetrics
  dateIsInGroup(date: Date, groupIndex: number): boolean
  nextSlot(slot: Date): Date
  closestSlotToPosition(percent: number): Date
  closestSlotFromPoint(point: { y: number }, boundaryRect: DOMRect): Date
  closestSlotFromDate(date: Date, offset?: number): Date
  startsBeforeDay(date: Date): boolean
  startsAfterDay(date: Date): boolean
  startsBefore(date: Date): boolean
  startsAfter(date: Date): boolean
  getRange(
    rangeStart: Date,
    rangeEnd: Date,
    ignoreMin?: boolean,
    ignoreMax?: boolean,
  ): {
    top: number
    height: number
    start: number
    startDate: Date
    end: number
    endDate: Date
  }
  getCurrentTimePosition(now: Date): number
}

function getKey({ min, max, step, timeslots, localizer }: TimeSlotMetricsOptions): string {
  return `${+localizer.startOf(min, "minutes")}${+localizer.startOf(max, "minutes")}${step}-${timeslots}`
}

export function getTimeSlotMetrics(options: TimeSlotMetricsOptions): ITimeSlotMetrics {
  const { min: start, max: end, step, timeslots, localizer } = options
  const key = getKey(options)

  const totalMin = 1 + localizer.getTotalMin(start, end)
  const minutesFromMidnight = localizer.getMinutesFromMidnight(start)
  const numGroups = Math.ceil((totalMin - 1) / (step * timeslots))
  const numSlots = numGroups * timeslots

  const groups: Date[][] = new Array(numGroups)
  const slots: Date[] = new Array(numSlots)

  for (let grp = 0; grp < numGroups; grp++) {
    groups[grp] = new Array(timeslots)
    for (let slot = 0; slot < timeslots; slot++) {
      const slotIdx = grp * timeslots + slot
      const minFromStart = slotIdx * step
      slots[slotIdx] = groups[grp][slot] = localizer.getSlotDate(
        start,
        minutesFromMidnight,
        minFromStart,
      )
    }
  }

  // Extra slot at the end for selection up to day end
  const lastSlotMinFromStart = slots.length * step
  slots.push(localizer.getSlotDate(start, minutesFromMidnight, lastSlotMinFromStart))

  function positionFromDate(date: Date): number {
    const d = localizer.diff(start, date, "minutes") + localizer.getDstOffset(start, date)
    return Math.min(d, totalMin)
  }

  return {
    groups,

    update(args: TimeSlotMetricsOptions) {
      if (getKey(args) !== key) return getTimeSlotMetrics(args)
      return this
    },

    dateIsInGroup(date: Date, groupIndex: number) {
      const nextGroup = groups[groupIndex + 1]
      return localizer.inRange(
        date,
        groups[groupIndex][0],
        nextGroup ? nextGroup[0] : end,
        "minutes",
      )
    },

    nextSlot(slot: Date) {
      const idx = slots.findIndex((s) => s === slot || localizer.eq(s, slot))
      let next = slots[Math.min(idx + 1, slots.length - 1)]
      if (localizer.eq(next, slot)) {
        next = localizer.add(slot, step, "minutes")
      }
      return next
    },

    closestSlotToPosition(percent: number) {
      const slot = Math.min(slots.length - 1, Math.max(0, Math.floor(percent * numSlots)))
      return slots[slot]
    },

    closestSlotFromPoint(point: { y: number }, boundaryRect: DOMRect) {
      const range = Math.abs(boundaryRect.top - boundaryRect.bottom)
      return this.closestSlotToPosition((point.y - boundaryRect.top) / range)
    },

    closestSlotFromDate(date: Date, offset: number = 0) {
      if (localizer.lt(date, start, "minutes")) return slots[0]
      if (localizer.gt(date, end, "minutes")) return slots[slots.length - 1]
      const diffMins = localizer.diff(start, date, "minutes")
      return slots[(diffMins - (diffMins % step)) / step + offset]
    },

    startsBeforeDay(date: Date) {
      return localizer.lt(date, start, "day")
    },

    startsAfterDay(date: Date) {
      return localizer.gt(date, end, "day")
    },

    startsBefore(date: Date) {
      return localizer.lt(localizer.merge(start, date), start, "minutes")
    },

    startsAfter(date: Date) {
      return localizer.gt(localizer.merge(end, date), end, "minutes")
    },

    getRange(rangeStart: Date, rangeEnd: Date, ignoreMin?: boolean, ignoreMax?: boolean) {
      if (!ignoreMin) rangeStart = localizer.min(end, localizer.max(start, rangeStart))
      if (!ignoreMax) rangeEnd = localizer.min(end, localizer.max(start, rangeEnd))

      const rangeStartMin = positionFromDate(rangeStart)
      const rangeEndMin = positionFromDate(rangeEnd)
      const top =
        rangeEndMin > step * numSlots && !localizer.eq(end, rangeEnd)
          ? ((rangeStartMin - step) / (step * numSlots)) * 100
          : (rangeStartMin / (step * numSlots)) * 100

      return {
        top,
        height: (rangeEndMin / (step * numSlots)) * 100 - top,
        start: positionFromDate(rangeStart),
        startDate: rangeStart,
        end: positionFromDate(rangeEnd),
        endDate: rangeEnd,
      }
    },

    getCurrentTimePosition(now: Date) {
      const rangeStartMin = positionFromDate(now)
      return (rangeStartMin / (step * numSlots)) * 100
    },
  }
}

/**
 * DayEventLayout — dispatches to the correct layout algorithm.
 */

import type { Accessors, CalendarEvent, DayLayoutAlgorithm, StyledEvent } from "../types"
import type { ITimeSlotMetrics } from "./time-slot-metrics"
import overlapLayout from "./layout-algorithms/overlap"
import noOverlapLayout from "./layout-algorithms/no-overlap"

const algorithms: Record<string, typeof overlapLayout> = {
  overlap: overlapLayout,
  "no-overlap": noOverlapLayout,
}

export function getStyledEvents({
  events,
  minimumStartDifference,
  slotMetrics,
  accessors,
  dayLayoutAlgorithm = "overlap",
}: {
  events: CalendarEvent[]
  minimumStartDifference: number
  slotMetrics: ITimeSlotMetrics
  accessors: Accessors
  dayLayoutAlgorithm?: DayLayoutAlgorithm
}): StyledEvent[] {
  if (typeof dayLayoutAlgorithm === "function") {
    return dayLayoutAlgorithm({
      events: events.map((e) => ({ event: e, style: { top: 0, height: 0, width: 0, xOffset: 0 } })),
      minimumStartDifference,
      slotMetrics: slotMetrics as never,
      accessors,
    })
  }

  const algorithm = algorithms[dayLayoutAlgorithm]
  if (!algorithm) return []

  return algorithm({
    events,
    minimumStartDifference,
    slotMetrics,
    accessors,
  })
}

/**
 * Resource grouping utilities.
 */

import type { Accessors, CalendarEvent, Resource } from "../types"

export const NONE = {} as Resource

export interface ResourceManager<TEvent extends CalendarEvent = CalendarEvent> {
  map<T>(fn: (resource: [string | number | typeof NONE, Resource | null], index: number) => T): T[]
  groupEvents(events: TEvent[]): Map<string | number | typeof NONE, TEvent[]>
}

export function Resources<TEvent extends CalendarEvent>(
  resources: Resource[] | undefined,
  accessors: Accessors<TEvent>,
): ResourceManager<TEvent> {
  return {
    map<T>(fn: (resource: [string | number | typeof NONE, Resource | null], index: number) => T): T[] {
      if (!resources) return [fn([NONE as unknown as string, null], 0)]
      return resources.map((resource, idx) =>
        fn([accessors.resourceId?.(resource as unknown as TEvent) ?? (resource.id as string), resource], idx),
      )
    },

    groupEvents(events: TEvent[]) {
      const eventsByResource = new Map<string | number | typeof NONE, TEvent[]>()

      if (!resources) {
        eventsByResource.set(NONE as unknown as string, events)
        return eventsByResource
      }

      for (const event of events) {
        const id = (accessors.resource?.(event) as string | number | Array<string | number>) || NONE
        if (Array.isArray(id)) {
          for (const item of id) {
            const resourceEvents = eventsByResource.get(item) || []
            resourceEvents.push(event)
            eventsByResource.set(item, resourceEvents)
          }
        } else {
          const resourceEvents = eventsByResource.get(id as string | number) || []
          resourceEvents.push(event)
          eventsByResource.set(id as string | number, resourceEvents)
        }
      }
      return eventsByResource
    },
  }
}

/**
 * Selection — low-level pointer interaction engine for calendar.
 * Handles mouse/touch click, drag-select, double-click, and long-press.
 * Fully TypeScript, no external dependencies.
 */

type SelectionHandler = (...args: unknown[]) => void

interface Point {
  x: number
  y: number
  clientX: number
  clientY: number
}

export interface SelectionBounds {
  top: number
  left: number
  right: number
  bottom: number
  x: number
  y: number
}

export function getBoundsForNode(node: HTMLElement): SelectionBounds {
  const rect = node.getBoundingClientRect()
  return {
    top: rect.top,
    left: rect.left,
    right: rect.left + rect.width,
    bottom: rect.top + rect.height,
    x: rect.left + rect.width / 2,
    y: rect.top + rect.height / 2,
  }
}

export function getEventNodeFromPoint(
  node: HTMLElement,
  point: { clientX: number; clientY: number },
): HTMLElement | null {
  const target = document.elementFromPoint(point.clientX, point.clientY)
  return target?.closest?.("[data-event]") as HTMLElement | null
}

export function getShowMoreNodeFromPoint(
  node: HTMLElement,
  point: { clientX: number; clientY: number },
): HTMLElement | null {
  const target = document.elementFromPoint(point.clientX, point.clientY)
  return target?.closest?.("[data-show-more]") as HTMLElement | null
}

export function isEvent(node: HTMLElement, point: { clientX: number; clientY: number }): boolean {
  return !!getEventNodeFromPoint(node, point)
}

export function isShowMore(node: HTMLElement, point: { clientX: number; clientY: number }): boolean {
  return !!getShowMoreNodeFromPoint(node, point)
}

export function objectsCollide(
  nodeA: SelectionBounds,
  nodeB: SelectionBounds,
  tolerance: number = 0,
): boolean {
  return !(
    nodeA.bottom - tolerance < nodeB.top ||
    nodeA.top + tolerance > nodeB.bottom ||
    nodeA.right - tolerance < nodeB.left ||
    nodeA.left + tolerance > nodeB.right
  )
}

function pointInBox(box: SelectionBounds, point: { x: number; y: number }): boolean {
  return point.y >= box.top && point.y <= box.bottom && point.x >= box.left && point.x <= box.right
}

function getEventCoordinates(e: MouseEvent | TouchEvent): Point {
  if ("touches" in e && e.touches.length > 0) {
    const touch = e.touches[0]
    return { x: touch.pageX, y: touch.pageY, clientX: touch.clientX, clientY: touch.clientY }
  }
  if ("changedTouches" in e && e.changedTouches.length > 0) {
    const touch = e.changedTouches[0]
    return { x: touch.pageX, y: touch.pageY, clientX: touch.clientX, clientY: touch.clientY }
  }
  const mouse = e as MouseEvent
  return { x: mouse.pageX, y: mouse.pageY, clientX: mouse.clientX, clientY: mouse.clientY }
}

const CLICK_THRESHOLD = 5
const LONG_PRESS_THRESHOLD = 250

export class Selection {
  private node: HTMLElement
  private longPressThreshold: number
  private listeners: Map<string, Set<SelectionHandler>>
  private cleanups: Array<() => void>
  private selecting: boolean
  private initialPoint: Point | null
  private longPressTimer: ReturnType<typeof setTimeout> | null

  constructor(
    node: HTMLElement,
    options: { longPressThreshold?: number } = {},
  ) {
    this.node = node
    this.longPressThreshold = options.longPressThreshold ?? LONG_PRESS_THRESHOLD
    this.listeners = new Map()
    this.cleanups = []
    this.selecting = false
    this.initialPoint = null
    this.longPressTimer = null

    this._addListeners()
  }

  on(type: string, handler: SelectionHandler): this {
    if (!this.listeners.has(type)) {
      this.listeners.set(type, new Set())
    }
    this.listeners.get(type)!.add(handler)
    return this
  }

  off(type: string, handler: SelectionHandler): this {
    this.listeners.get(type)?.delete(handler)
    return this
  }

  emit(type: string, ...args: unknown[]): void {
    this.listeners.get(type)?.forEach((fn) => fn(...args))
  }

  teardown(): void {
    this._clearLongPress()
    this.cleanups.forEach((fn) => fn())
    this.cleanups = []
    this.listeners.clear()
    this.selecting = false
  }

  isSelected(node: HTMLElement): boolean {
    return false // placeholder for external use
  }

  private _listen(
    target: EventTarget,
    event: string,
    handler: EventListenerOrEventListenerObject,
    options?: AddEventListenerOptions,
  ): void {
    target.addEventListener(event, handler, options)
    this.cleanups.push(() => target.removeEventListener(event, handler, options))
  }

  private _addListeners(): void {
    this._listen(this.node, "mousedown", this._onMouseDown as EventListener)
    this._listen(this.node, "touchstart", this._onTouchStart as EventListener, { passive: false })

    // Keyboard escape
    this._listen(document, "keydown", ((e: KeyboardEvent) => {
      if (e.key === "Escape") {
        this.selecting = false
        this._clearLongPress()
        this.emit("reset")
      }
    }) as EventListener)
  }

  private _onMouseDown = (e: MouseEvent): void => {
    if (e.button !== 0) return // left button only

    const point = getEventCoordinates(e)
    this.initialPoint = point

    const onMove = (e: MouseEvent) => {
      const current = getEventCoordinates(e)
      if (!this.selecting && this._isClick(this.initialPoint!, current)) return

      if (!this.selecting) {
        this.selecting = true
        this.emit("selectStart", this.initialPoint)
      }
      this.emit("selecting", {
        ...current,
        initial: this.initialPoint,
      })
    }

    const onUp = (e: MouseEvent) => {
      document.removeEventListener("mousemove", onMove)
      document.removeEventListener("mouseup", onUp)

      const point = getEventCoordinates(e)

      if (this.selecting) {
        this.selecting = false
        this.emit("select", {
          ...point,
          initial: this.initialPoint,
        })
        this.emit("reset")
      } else {
        // It's a click
        if (!this._isClick(this.initialPoint!, point)) return
        this.emit("click", point)
      }
    }

    document.addEventListener("mousemove", onMove)
    document.addEventListener("mouseup", onUp)
  }

  private _onTouchStart = (e: TouchEvent): void => {
    const point = getEventCoordinates(e)
    this.initialPoint = point

    // Start long press timer
    this.longPressTimer = setTimeout(() => {
      this.selecting = true
      this.emit("selectStart", point)
    }, this.longPressThreshold)

    const onMove = (e: TouchEvent) => {
      const current = getEventCoordinates(e)
      this._clearLongPress()

      if (!this.selecting && !this._isClick(this.initialPoint!, current)) {
        // Scrolling, not selecting
        return
      }

      if (this.selecting) {
        e.preventDefault()
        this.emit("selecting", {
          ...current,
          initial: this.initialPoint,
        })
      }
    }

    const onEnd = (e: TouchEvent) => {
      document.removeEventListener("touchmove", onMove)
      document.removeEventListener("touchend", onEnd)
      this._clearLongPress()

      const point = getEventCoordinates(e)

      if (this.selecting) {
        this.selecting = false
        this.emit("select", {
          ...point,
          initial: this.initialPoint,
        })
        this.emit("reset")
      } else {
        this.emit("click", point)
      }
    }

    document.addEventListener("touchmove", onMove, { passive: false })
    document.addEventListener("touchend", onEnd)
  }

  private _clearLongPress(): void {
    if (this.longPressTimer) {
      clearTimeout(this.longPressTimer)
      this.longPressTimer = null
    }
  }

  private _isClick(initial: Point, current: Point): boolean {
    return (
      Math.abs(current.x - initial.x) <= CLICK_THRESHOLD &&
      Math.abs(current.y - initial.y) <= CLICK_THRESHOLD
    )
  }
}

// ─── Selection helpers for date cells ─────────────────────────────────

export function slotWidth(rowBox: SelectionBounds, slots: number): number {
  return (rowBox.right - rowBox.left) / slots
}

export function getSlotAtX(
  rowBox: SelectionBounds,
  x: number,
  rtl: boolean,
  slots: number,
): number {
  const cellWidth = slotWidth(rowBox, slots)
  return rtl
    ? slots - 1 - Math.floor((x - rowBox.left) / cellWidth)
    : Math.floor((x - rowBox.left) / cellWidth)
}

export function dateCellSelection(
  start: number,
  rowBox: SelectionBounds,
  box: { x: number; y: number },
  slots: number,
  rtl: boolean,
): { startIdx: number; endIdx: number } {
  let stIdx = start
  let endIdx = getSlotAtX(rowBox, box.x, rtl, slots)

  if (stIdx > endIdx) {
    ;[stIdx, endIdx] = [endIdx, stIdx]
  }

  stIdx = Math.max(stIdx, 0)
  endIdx = Math.min(endIdx, slots - 1)

  return { startIdx: stIdx, endIdx }
}

/**
 * Overlap layout algorithm — allows events to visually overlap.
 * Ported from react-big-calendar to TypeScript.
 */

import type { Accessors, CalendarEvent, StyledEvent } from "../../types"
import type { ITimeSlotMetrics } from "../time-slot-metrics"

interface LayoutEvent {
  start: number
  end: number
  startMs: number
  endMs: number
  top: number
  height: number
  data: CalendarEvent

  // Tree structure
  rows?: LayoutEvent[]
  leaves?: LayoutEvent[]
  container?: LayoutEvent
  row?: LayoutEvent
}

function createLayoutEvent(
  data: CalendarEvent,
  accessors: Accessors,
  slotMetrics: ITimeSlotMetrics,
): LayoutEvent {
  const { start, startDate, end, endDate, top, height } = slotMetrics.getRange(
    accessors.start(data),
    accessors.end(data),
  )
  return {
    start,
    end,
    startMs: +startDate,
    endMs: +endDate,
    top,
    height,
    data,
  }
}

function getWidth(event: LayoutEvent): number {
  if (event.rows) {
    const columns =
      event.rows.reduce((max, row) => Math.max(max, (row.leaves?.length ?? 0) + 1), 0) + 1
    return 100 / columns
  }
  if (event.leaves) {
    const available = 100 - getWidth(event.container!)
    return available / (event.leaves.length + 1)
  }
  return getWidth(event.row!)
}

function getOverlapWidth(event: LayoutEvent): number {
  const noOverlap = getWidth(event)
  const overlap = Math.min(100, getWidth(event) * 1.7)

  if (event.rows) return overlap
  if (event.leaves) return event.leaves.length > 0 ? overlap : noOverlap

  const { leaves } = event.row!
  const index = leaves!.indexOf(event)
  return index === leaves!.length - 1 ? noOverlap : overlap
}

function getXOffset(event: LayoutEvent): number {
  if (event.rows) return 0
  if (event.leaves) return getWidth(event.container!)

  const { leaves, row } = event
  const rowXOffset = getXOffset(event.row!)
  const rowWidth = getWidth(event.row!)
  const index = event.row!.leaves!.indexOf(event) + 1
  return rowXOffset + index * rowWidth
}

function onSameRow(a: LayoutEvent, b: LayoutEvent, minimumStartDifference: number): boolean {
  return (
    Math.abs(b.start - a.start) < minimumStartDifference ||
    (b.start > a.start && b.start < a.end)
  )
}

function sortByRender(events: LayoutEvent[]): LayoutEvent[] {
  const sortedByTime = [...events].sort(
    (a, b) => a.startMs - b.startMs || b.endMs - a.endMs,
  )

  const sorted: LayoutEvent[] = []
  while (sortedByTime.length > 0) {
    const event = sortedByTime.shift()!
    sorted.push(event)

    for (let i = 0; i < sortedByTime.length; i++) {
      const test = sortedByTime[i]
      if (event.endMs > test.startMs) continue
      if (i > 0) {
        const [moved] = sortedByTime.splice(i, 1)
        sorted.push(moved)
      }
      break
    }
  }
  return sorted
}

export default function overlapLayout({
  events,
  minimumStartDifference,
  slotMetrics,
  accessors,
}: {
  events: CalendarEvent[]
  minimumStartDifference: number
  slotMetrics: ITimeSlotMetrics
  accessors: Accessors
}): StyledEvent[] {
  const proxies = events.map((e) => createLayoutEvent(e, accessors, slotMetrics))

  // Sort by start time, then by longest event first
  const sorted = proxies.sort(
    (a, b) => a.startMs - b.startMs || b.endMs - a.endMs,
  )

  // Build the tree of containers → rows → leaves
  const containers: LayoutEvent[] = []

  for (const event of sorted) {
    const container = containers.find(
      (c) =>
        c.end > event.start ||
        Math.abs(event.start - c.start) < minimumStartDifference,
    )

    if (!container) {
      event.rows = []
      containers.push(event)
      continue
    }

    // Check if it belongs to an existing row
    const row = container.rows!.find((r) => onSameRow(r, event, minimumStartDifference))

    if (row) {
      row.leaves!.push(event)
      event.row = row
      event.container = container
      container.end = Math.max(container.end, event.end)
    } else {
      event.leaves = []
      event.container = container
      container.rows!.push(event)
      container.end = Math.max(container.end, event.end)
    }
  }

  // Convert to styled events
  const rendered = sortByRender(sorted)
  return rendered.map((event) => ({
    event: event.data,
    style: {
      top: event.top,
      height: event.height,
      width: getOverlapWidth(event),
      xOffset: getXOffset(event),
    },
  }))
}

/**
 * No-overlap layout algorithm — resizes events so they don't visually overlap.
 * Ported from react-big-calendar to TypeScript.
 */

import type { Accessors, CalendarEvent, StyledEvent } from "../../types"
import type { ITimeSlotMetrics } from "../time-slot-metrics"
import overlapLayout from "./overlap"

interface StyledNode extends StyledEvent {
  friends: StyledNode[]
  idx?: number
  size?: number
}

function getMaxIdxDFS(node: StyledNode, maxIdx: number, visited: StyledNode[]): number {
  for (const friend of node.friends) {
    if (visited.includes(friend)) continue
    maxIdx = Math.max(maxIdx, friend.idx ?? 0)
    visited.push(friend)
    const newIdx = getMaxIdxDFS(friend, maxIdx, visited)
    maxIdx = Math.max(maxIdx, newIdx)
  }
  return maxIdx
}

export default function noOverlapLayout({
  events,
  minimumStartDifference,
  slotMetrics,
  accessors,
}: {
  events: CalendarEvent[]
  minimumStartDifference: number
  slotMetrics: ITimeSlotMetrics
  accessors: Accessors
}): StyledEvent[] {
  const styledEvents: StyledNode[] = overlapLayout({
    events,
    minimumStartDifference,
    slotMetrics,
    accessors,
  }).map((se) => ({
    ...se,
    friends: [],
  }))

  // Sort by top position, then by height
  styledEvents.sort((a, b) => {
    if (a.style.top !== b.style.top) return a.style.top > b.style.top ? 1 : -1
    if (a.style.height !== b.style.height)
      return a.style.top + a.style.height < b.style.top + b.style.height ? 1 : -1
    return 0
  })

  // Reset properties
  for (const se of styledEvents) {
    se.friends = []
    delete se.idx
    delete se.size
  }

  // Find overlapping friends
  for (let i = 0; i < styledEvents.length - 1; i++) {
    const se1 = styledEvents[i]
    const y1 = se1.style.top
    const y2 = se1.style.top + se1.style.height

    for (let j = i + 1; j < styledEvents.length; j++) {
      const se2 = styledEvents[j]
      const y3 = se2.style.top
      const y4 = se2.style.top + se2.style.height

      if ((y3 >= y1 && y4 <= y2) || (y4 > y1 && y4 <= y2) || (y3 >= y1 && y3 < y2)) {
        se1.friends.push(se2)
        se2.friends.push(se1)
      }
    }
  }

  // Assign column indices via bitmap
  for (const se of styledEvents) {
    const bitmap = new Array(100).fill(1)
    for (const friend of se.friends) {
      if (friend.idx !== undefined) bitmap[friend.idx] = 0
    }
    se.idx = bitmap.indexOf(1)
  }

  // Calculate sizes
  for (const se of styledEvents) {
    if (se.size) continue
    const allFriends: StyledNode[] = []
    const maxIdx = getMaxIdxDFS(se, 0, allFriends)
    const size = 100 / (maxIdx + 1)
    se.size = size
    for (const friend of allFriends) friend.size = size
  }

  // Apply final styles
  for (const e of styledEvents) {
    e.style.xOffset = (e.idx ?? 0) * (e.size ?? 100)
    e.style.width = e.size ?? 100

    // Stretch to max width when possible
    let maxIdx = 0
    for (const friend of e.friends) {
      maxIdx = Math.max(maxIdx, friend.idx ?? 0)
    }
    if (maxIdx <= (e.idx ?? 0)) {
      e.style.width = 100 - e.style.xOffset
    }
  }

  return styledEvents.map(({ event, style }) => ({ event, style }))
}

"use client"

import { useEffect, useRef } from "react"

/**
 * Hook that triggers a callback when a click occurs outside the referenced element.
 */
export function useClickOutside(
  ref: React.RefObject<HTMLElement | null>,
  callback: () => void,
): void {
  const callbackRef = useRef(callback)
  callbackRef.current = callback

  useEffect(() => {
    function handleClick(e: MouseEvent) {
      if (ref.current && !ref.current.contains(e.target as Node)) {
        callbackRef.current()
      }
    }
    document.addEventListener("mousedown", handleClick)
    return () => document.removeEventListener("mousedown", handleClick)
  }, [ref])
}

"use client"

import { useState, useCallback, useRef, type Dispatch, type SetStateAction } from "react"

/**
 * Hook for controlled/uncontrolled state — replacement for the old `uncontrollable` library.
 * If `controlledValue` is provided, it acts as a controlled component.
 * Otherwise, it manages its own internal state starting from `defaultValue`.
 */
export function useControllableState<T>(
  controlledValue: T | undefined,
  defaultValue: T,
  onChange?: (value: T) => void,
): [T, Dispatch<SetStateAction<T>>] {
  const [internal, setInternal] = useState(defaultValue)
  const isControlled = controlledValue !== undefined

  const value = isControlled ? controlledValue : internal

  const setValue = useCallback(
    (newValue: T | ((prev: T) => T)) => {
      const resolved = typeof newValue === "function"
        ? (newValue as (prev: T) => T)(value)
        : newValue

      if (!isControlled) {
        setInternal(resolved)
      }
      onChange?.(resolved)
    },
    [isControlled, onChange, value],
  )

  return [value, setValue]
}

"use client"

import * as React from "react"
import { createContext, useContext, useRef, useCallback, useState, useEffect } from "react"
import type { CalendarEvent, EventInteractionArgs, Accessor } from "../types"

// ─── DnD State ────────────────────────────────────────────────────
export type DragAction = "move" | "resize"

export interface DragState<TEvent = CalendarEvent> {
  /** The event being dragged */
  event: TEvent
  /** Whether we're moving or resizing */
  action: DragAction
  /** For resize: direction (only "DOWN" for now) */
  direction?: "UP" | "DOWN"
  /** Accessor-resolved start of the event (set once at beginDrag) */
  resolvedStart?: Date
  /** Accessor-resolved end of the event (set once at beginDrag) */
  resolvedEnd?: Date
  /** Preview start date while dragging */
  previewStart?: Date
  /** Preview end date while dragging */
  previewEnd?: Date
  /** Resource column being hovered */
  previewResourceId?: string | number
}

export interface DnDContextValue<TEvent = CalendarEvent> {
  /** Current drag state, null if not dragging */
  dragState: DragState<TEvent> | null
  /** Start a drag operation */
  beginDrag: (event: TEvent, action: DragAction, direction?: "UP" | "DOWN", resolvedStart?: Date, resolvedEnd?: Date) => void
  /** Update the preview position during drag */
  updatePreview: (start: Date, end: Date, resourceId?: string | number) => void
  /** End drag — fires the callback */
  endDrag: () => void
  /** Cancel drag — no callback */
  cancelDrag: () => void
  /** Whether DnD is enabled */
  enabled: boolean
  /** Per-event: is this event draggable? */
  isDraggable: (event: TEvent) => boolean
  /** Per-event: is this event resizable? */
  isResizable: (event: TEvent) => boolean
  /** Callbacks */
  onEventDrop?: (args: EventInteractionArgs<TEvent>) => void
  onEventResize?: (args: EventInteractionArgs<TEvent>) => void
  onDragStart?: (args: { event: TEvent; action: DragAction; direction?: "UP" | "DOWN" }) => void
  onDragEnd?: (args: { event: TEvent; action: DragAction }) => void
}

const DnDContext = createContext<DnDContextValue<any>>({
  dragState: null,
  beginDrag: () => {},
  updatePreview: () => {},
  endDrag: () => {},
  cancelDrag: () => {},
  enabled: false,
  isDraggable: () => true,
  isResizable: () => true,
})

export function useDnD<TEvent extends CalendarEvent = CalendarEvent>() {
  return useContext(DnDContext) as DnDContextValue<TEvent>
}

// ─── Provider ─────────────────────────────────────────────────────
export interface DnDProviderProps<TEvent extends CalendarEvent = CalendarEvent> {
  children: React.ReactNode
  enabled: boolean
  draggableAccessor?: Accessor<TEvent, boolean>
  resizableAccessor?: Accessor<TEvent, boolean>
  onEventDrop?: (args: EventInteractionArgs<TEvent>) => void
  onEventResize?: (args: EventInteractionArgs<TEvent>) => void
  onDragStart?: (args: { event: TEvent; action: DragAction; direction?: "UP" | "DOWN" }) => void
  onDragEnd?: (args: { event: TEvent; action: DragAction }) => void
}

function resolveAccessor<TEvent, TVal>(acc: Accessor<TEvent, TVal> | undefined, event: TEvent, fallback: TVal): TVal {
  if (acc === undefined) return fallback
  if (typeof acc === "function") return (acc as (e: TEvent) => TVal)(event)
  if (typeof acc === "string" && event != null && typeof event === "object") {
    return (event as Record<string, unknown>)[acc as string] as TVal
  }
  return fallback
}

export function DnDProvider<TEvent extends CalendarEvent = CalendarEvent>({
  children,
  enabled,
  draggableAccessor,
  resizableAccessor,
  onEventDrop,
  onEventResize,
  onDragStart,
  onDragEnd,
}: DnDProviderProps<TEvent>) {
  const [dragState, setDragState] = useState<DragState<TEvent> | null>(null)
  const dragRef = useRef<DragState<TEvent> | null>(null)

  const beginDrag = useCallback(
    (event: TEvent, action: DragAction, direction?: "UP" | "DOWN", resolvedStart?: Date, resolvedEnd?: Date) => {
      const state: DragState<TEvent> = { event, action, direction, resolvedStart, resolvedEnd }
      dragRef.current = state
      setDragState(state)
      onDragStart?.({ event, action, direction })
    },
    [onDragStart],
  )

  const updatePreview = useCallback(
    (start: Date, end: Date, resourceId?: string | number) => {
      if (!dragRef.current) return
      const next = { ...dragRef.current, previewStart: start, previewEnd: end, previewResourceId: resourceId }
      dragRef.current = next
      setDragState(next)
    },
    [],
  )

  const endDrag = useCallback(() => {
    const state = dragRef.current
    if (!state) return
    const { event, action, previewStart, previewEnd, previewResourceId } = state

    if (previewStart && previewEnd) {
      const args: EventInteractionArgs<TEvent> = {
        event,
        start: previewStart,
        end: previewEnd,
        resourceId: previewResourceId,
      }
      if (action === "move") {
        onEventDrop?.(args)
      } else if (action === "resize") {
        onEventResize?.(args)
      }
    }

    onDragEnd?.({ event, action })
    dragRef.current = null
    setDragState(null)
  }, [onEventDrop, onEventResize, onDragEnd])

  const cancelDrag = useCallback(() => {
    const state = dragRef.current
    if (state) {
      onDragEnd?.({ event: state.event, action: state.action })
    }
    dragRef.current = null
    setDragState(null)
  }, [onDragEnd])

  const isDraggable = useCallback(
    (event: TEvent) => resolveAccessor(draggableAccessor, event, true),
    [draggableAccessor],
  )

  const isResizable = useCallback(
    (event: TEvent) => resolveAccessor(resizableAccessor, event, true),
    [resizableAccessor],
  )

  const value: DnDContextValue<TEvent> = {
    dragState,
    beginDrag,
    updatePreview,
    endDrag,
    cancelDrag,
    enabled,
    isDraggable,
    isResizable,
    onEventDrop,
    onEventResize,
    onDragStart,
    onDragEnd,
  }

  // Global pointer-up safety net: if the user releases outside any drop target
  // (e.g. outside calendar bounds during a month-view drag), clean up the drag state.
  useEffect(() => {
    if (!dragState) return
    const handleGlobalPointerUp = () => {
      // If there's an active drag with a preview, complete it; otherwise cancel.
      if (dragRef.current?.previewStart && dragRef.current?.previewEnd) {
        endDrag()
      } else {
        cancelDrag()
      }
    }
    window.addEventListener("pointerup", handleGlobalPointerUp)
    return () => window.removeEventListener("pointerup", handleGlobalPointerUp)
  }, [dragState, endDrag, cancelDrag])

  return React.createElement(DnDContext.Provider, { value }, children)
}

