  return (
    <div className="flex items-center justify-between gap-4 px-2 py-2">
      {/* Left: navigation */}
      <div className="flex items-center gap-1">
        <button
          type="button"
          onClick={() => onNavigate(navigate.TODAY as NavigateAction)}
          className={cn(
            "inline-flex items-center justify-center rounded-md text-sm font-medium h-8 px-3",
            "border border-input bg-background hover:bg-accent hover:text-accent-foreground",
            "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring",
            "transition-colors",
          )}
        >
          {messages.today}
        </button>
        <button
          type="button"
          onClick={() => onNavigate(navigate.PREVIOUS as NavigateAction)}
          className={cn(
            "inline-flex items-center justify-center rounded-md h-8 w-8",
            "border border-input bg-background hover:bg-accent hover:text-accent-foreground",
            "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring",
            "transition-colors",
          )}
          aria-label={messages.previous}
        >
          <ChevronLeft className="h-4 w-4" />
        </button>
        <button
          type="button"
          onClick={() => onNavigate(navigate.NEXT as NavigateAction)}
          className={cn(
            "inline-flex items-center justify-center rounded-md h-8 w-8",
            "border border-input bg-background hover:bg-accent hover:text-accent-foreground",
            "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring",
            "transition-colors",
          )}
          aria-label={messages.next}
        >
          <ChevronRight className="h-4 w-4" />
        </button>
      </div>

      {/* Center: label + zoom */}
      <div className="flex items-center gap-2">
        {showZoom && onZoomIn && (
          <button
            type="button"
            disabled={!canZoomIn}
            onClick={onZoomIn}
            className={cn(
              "inline-flex items-center justify-center rounded-md h-7 w-7",
              "border border-input bg-background hover:bg-accent hover:text-accent-foreground",
              "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring",
              "transition-colors",
              !canZoomIn && "opacity-40 pointer-events-none",
            )}
            aria-label="Zoom in"
            title="Zoom in (finer time slots)"
          >
            <ZoomIn className="h-3.5 w-3.5" />
          </button>
        )}
        <h2 className="text-base font-semibold text-foreground whitespace-nowrap">
          {label}
        </h2>
        {showZoom && onZoomOut && (
          <button
            type="button"
            disabled={!canZoomOut}
            onClick={onZoomOut}
            className={cn(
              "inline-flex items-center justify-center rounded-md h-7 w-7",
              "border border-input bg-background hover:bg-accent hover:text-accent-foreground",
              "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring",
              "transition-colors",
              !canZoomOut && "opacity-40 pointer-events-none",
            )}
            aria-label="Zoom out"
            title="Zoom out (coarser time slots)"
          >
            <ZoomOut className="h-3.5 w-3.5" />
          </button>
        )}
      </div>

      {/* Right: view switcher */}
      <ToggleGroupPrimitive.Root
        type="single"
        value={view}
        onValueChange={(value: string) => {
          if (value) onView(value as View)
        }}
        className="inline-flex items-center rounded-md border border-input bg-background"
      >
        {views.map((v) => (
          <ToggleGroupPrimitive.Item
            key={v}
            value={v}
            className={cn(
              "inline-flex items-center justify-center text-sm font-medium h-8 px-3",
              "first:rounded-l-md last:rounded-r-md",
              "hover:bg-accent hover:text-accent-foreground",
              "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-1",
              "transition-colors",
              "data-[state=on]:bg-primary data-[state=on]:text-primary-foreground",
            )}
          >
            {messages[v as keyof typeof messages] || v}
          </ToggleGroupPrimitive.Item>
        ))}
      </ToggleGroupPrimitive.Root>
    </div>
  )
}

"use client"

import * as React from "react"
import { useRef, useCallback } from "react"
import { cn } from "@/lib/utils"
import type {
  CalendarEvent,
  Accessors,
  Getters,
  DateLocalizer,
  CalendarComponents,
} from "../types"
import { isSelected as checkSelected } from "../helpers"
import { useDnD } from "../hooks/use-dnd"

// ─── EventCell (month / all-day row event) ────────────────────────────

export interface EventCellProps<TEvent extends CalendarEvent = CalendarEvent> {
  event: TEvent
  selected?: TEvent
  isAllDay?: boolean
  continuesPrior?: boolean
  continuesAfter?: boolean
  accessors: Accessors<TEvent>
  getters: Getters<TEvent>
  localizer: DateLocalizer
  components: CalendarComponents<TEvent>
  slotStart?: Date
  slotEnd?: Date
  onSelect?: (event: TEvent, e: React.SyntheticEvent) => void
  onDoubleClick?: (event: TEvent, e: React.SyntheticEvent) => void
  onKeyPress?: (event: TEvent, e: React.KeyboardEvent) => void
  resizable?: boolean
}

export function EventCell<TEvent extends CalendarEvent = CalendarEvent>({
  event,
  selected,
  isAllDay,
  continuesPrior,
  continuesAfter,
  accessors,
  getters,
  localizer,
  components,
  slotStart,
  slotEnd,
  onSelect,
  onDoubleClick,
  onKeyPress,
}: EventCellProps<TEvent>) {
  const title = accessors.title(event)
  const tooltip = accessors.tooltip(event)
  const end = accessors.end(event)
  const start = accessors.start(event)
  const isSelectedEvent = checkSelected(event, selected)
  const { className: userClassName, style: userStyle } = getters.eventProp(
    event,
    start,
    end,
    isSelectedEvent,
  )
  const { enabled: dndEnabled, dragState, beginDrag, isDraggable } = useDnD<TEvent>()
  const canDrag = dndEnabled && isDraggable(event)
  const isDragging = dragState?.event === event

  const EventComponent = components.event

  // Month-view drag: start a "move" on pointerDown
  const pointerOrigin = useRef<{ x: number; y: number } | null>(null)
  const handlePointerDown = useCallback(
    (e: React.PointerEvent) => {
      if (!canDrag) return
      pointerOrigin.current = { x: e.clientX, y: e.clientY }
    },
    [canDrag],
  )
  const handlePointerMove = useCallback(
    (e: React.PointerEvent) => {
      if (!canDrag || !pointerOrigin.current) return
      const dx = Math.abs(e.clientX - pointerOrigin.current.x)
      const dy = Math.abs(e.clientY - pointerOrigin.current.y)
      if (dx + dy > 5) {
        beginDrag(event, "move", undefined, start, end)
        pointerOrigin.current = null
      }
    },
    [canDrag, beginDrag, event],
  )
  const handlePointerUp = useCallback(() => {
    pointerOrigin.current = null
  }, [])

  return (
    <div
      data-event
      tabIndex={0}
      title={tooltip || title}
      onClick={(e) => onSelect?.(event, e)}
      onDoubleClick={(e) => onDoubleClick?.(event, e)}
      onKeyDown={(e) => {
        if (e.key === "Enter" || e.key === " ") {
          e.preventDefault()
          onSelect?.(event, e)
        }
        onKeyPress?.(event, e)
      }}
      onPointerDown={handlePointerDown}
      onPointerMove={handlePointerMove}
      onPointerUp={handlePointerUp}
      style={userStyle}
      className={cn(
        "group relative cursor-pointer select-none rounded-md px-2 py-0.5 text-xs font-medium leading-tight",
        "bg-calendar-event text-calendar-event-foreground",
        "hover:opacity-90 transition-opacity",
        "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-1",
        isAllDay && "truncate",
        isSelectedEvent && "ring-2 ring-ring ring-offset-1",
        continuesPrior && "rounded-l-none",
        continuesAfter && "rounded-r-none",
        canDrag && "cursor-grab active:cursor-grabbing",
        isDragging && "opacity-50 ring-2 ring-primary",
        userClassName,
      )}
    >
      {EventComponent ? (
        <EventComponent
          event={event}
          title={title}
          isAllDay={isAllDay}
          localizer={localizer}
          slotStart={slotStart}
          slotEnd={slotEnd}
          continuesPrior={continuesPrior}
          continuesAfter={continuesAfter}
        />
      ) : (
        <span className="truncate">{title}</span>
      )}
    </div>
  )
}

// ─── TimeGridEvent (time-based views) ─────────────────────────────────

export interface TimeGridEventProps<TEvent extends CalendarEvent = CalendarEvent> {
  event: TEvent
  style: {
    top: number
    height: number
    width: number
    xOffset: number
  }
  label?: string
  selected?: TEvent
  isBackgroundEvent?: boolean
  continuesPrior?: boolean
  continuesAfter?: boolean
  accessors: Accessors<TEvent>
  getters: Getters<TEvent>
  localizer: DateLocalizer
  components: CalendarComponents<TEvent>
  rtl?: boolean
  /** The column date for this event (used for DnD calculations) */
  columnDate?: Date
  /** The min/max of the day column (for DnD time resolution) */
  columnMin?: Date
  columnMax?: Date
  /** Step in minutes */
  step?: number
  /** Resource id of the column */
  resource?: string | number
  onSelect?: (event: TEvent, e: React.SyntheticEvent) => void
  onDoubleClick?: (event: TEvent, e: React.SyntheticEvent) => void
  onKeyPress?: (event: TEvent, e: React.KeyboardEvent) => void
}

export function TimeGridEvent<TEvent extends CalendarEvent = CalendarEvent>({
  event,
  style,
  label,
  selected,
  isBackgroundEvent,
  continuesPrior,
  continuesAfter,
  accessors,
  getters,
  localizer,
  components,
  rtl,
  columnMin,
  columnMax,
  step = 30,
  resource,
  onSelect,
  onDoubleClick,
  onKeyPress,
}: TimeGridEventProps<TEvent>) {
  const title = accessors.title(event)
  const tooltip = accessors.tooltip(event)
  const end = accessors.end(event)
  const start = accessors.start(event)
  const isSelectedEvent = checkSelected(event, selected)
  const { className: userClassName, style: userStyle } = getters.eventProp(
    event,
    start,
    end,
    isSelectedEvent,
  )

  const { enabled: dndEnabled, dragState, beginDrag, updatePreview, endDrag, cancelDrag, isDraggable, isResizable } = useDnD<TEvent>()
  const canDrag = dndEnabled && isDraggable(event)
  const canResize = dndEnabled && isResizable(event)
  const isDragging = dragState?.event === event
  const eventRef = useRef<HTMLDivElement>(null)
  const dragOriginRef = useRef<{ y: number; action: "move" | "resize"; startTop: number; startHeight: number } | null>(null)

  const EventComponent = components.day?.event ?? components.event

  // ── Drag-to-move: pointer handlers on the event body ──
  const handleMovePointerDown = useCallback(
    (e: React.PointerEvent) => {
      if (!canDrag || isBackgroundEvent) return
      // Ignore if clicking the resize handle
      if ((e.target as HTMLElement).dataset.resizeHandle) return
      e.stopPropagation()
      dragOriginRef.current = { y: e.clientY, action: "move", startTop: style.top, startHeight: style.height }
    },
    [canDrag, isBackgroundEvent, style.top, style.height],
  )

  const handleMovePointerMove = useCallback(
    (e: React.PointerEvent) => {
      if (!dragOriginRef.current || dragOriginRef.current.action !== "move") return
      const dy = Math.abs(e.clientY - dragOriginRef.current.y)
      if (dy < 5 && !isDragging) return // deadzone

      if (!isDragging) {
        beginDrag(event, "move", undefined, start, end)
        ;(e.target as HTMLElement).setPointerCapture?.(e.pointerId)
      }

      // Calculate new time based on pointer position in the column
      const column = eventRef.current?.parentElement
      if (!column || !columnMin || !columnMax) return
      const bounds = column.getBoundingClientRect()
      const pct = Math.max(0, Math.min(1, (e.clientY - bounds.top) / bounds.height))
      const totalMinutes = (columnMax.getTime() - columnMin.getTime()) / 60000
      const minuteOffset = Math.round((pct * totalMinutes) / step) * step
      const newStart = new Date(columnMin.getTime() + minuteOffset * 60000)
      const duration = end.getTime() - start.getTime()
      const newEnd = new Date(newStart.getTime() + duration)

      updatePreview(newStart, newEnd, resource)
    },
    [isDragging, beginDrag, event, updatePreview, columnMin, columnMax, step, start, end, resource],
  )

  const handleMovePointerUp = useCallback(
    (e: React.PointerEvent) => {
      if (!dragOriginRef.current) return
      ;(e.target as HTMLElement).releasePointerCapture?.(e.pointerId)
      if (isDragging) {
        endDrag()
      }
      dragOriginRef.current = null
    },
    [isDragging, endDrag],
  )

  // ── Drag-to-resize: pointer handlers on the bottom handle ──
  const handleResizePointerDown = useCallback(
    (e: React.PointerEvent) => {
      if (!canResize || isBackgroundEvent) return
      e.stopPropagation()
      e.preventDefault()
      dragOriginRef.current = { y: e.clientY, action: "resize", startTop: style.top, startHeight: style.height }
      beginDrag(event, "resize", "DOWN", start, end)
      ;(e.target as HTMLElement).setPointerCapture(e.pointerId)
    },
    [canResize, isBackgroundEvent, style.top, style.height, beginDrag, event],
  )

  const handleResizePointerMove = useCallback(
    (e: React.PointerEvent) => {
      if (!dragOriginRef.current || dragOriginRef.current.action !== "resize") return
      const column = eventRef.current?.parentElement
      if (!column || !columnMin || !columnMax) return

      const bounds = column.getBoundingClientRect()
      const pct = Math.max(0, Math.min(1, (e.clientY - bounds.top) / bounds.height))
      const totalMinutes = (columnMax.getTime() - columnMin.getTime()) / 60000
      const minuteOffset = Math.round((pct * totalMinutes) / step) * step
      const newEnd = new Date(columnMin.getTime() + minuteOffset * 60000)
      // Don't allow resize to before start + one step
      const minEnd = new Date(start.getTime() + step * 60000)
      const clampedEnd = newEnd < minEnd ? minEnd : newEnd

      updatePreview(start, clampedEnd, resource)
    },
    [columnMin, columnMax, step, start, updatePreview, resource],
  )

  const handleResizePointerUp = useCallback(
    (e: React.PointerEvent) => {
      if (!dragOriginRef.current || dragOriginRef.current.action !== "resize") return
      ;(e.target as HTMLElement).releasePointerCapture(e.pointerId)
      endDrag()
      dragOriginRef.current = null
    },
    [endDrag],
  )

  // Escape to cancel
  const handleKeyDown = useCallback(
    (e: React.KeyboardEvent) => {
      if (e.key === "Escape" && isDragging) {
        cancelDrag()
        dragOriginRef.current = null
        return
      }
      if (e.key === "Enter" || e.key === " ") {
        e.preventDefault()
        onSelect?.(event, e)
      }
      onKeyPress?.(event, e)
    },
    [isDragging, cancelDrag, onSelect, onKeyPress, event],
  )

  // ── Compute displayed position (use preview when dragging) ──
  let displayTop = style.top
  let displayHeight = style.height
  if (isDragging && dragState?.previewStart && dragState?.previewEnd && columnMin && columnMax) {
    const totalMs = columnMax.getTime() - columnMin.getTime()
    if (totalMs > 0) {
      const previewTopMs = dragState.previewStart.getTime() - columnMin.getTime()
      const previewEndMs = dragState.previewEnd.getTime() - columnMin.getTime()
      displayTop = Math.max(0, (previewTopMs / totalMs) * 100)
      displayHeight = Math.max(0, ((previewEndMs - previewTopMs) / totalMs) * 100)
    }
  }

  const inlineStyle: React.CSSProperties = {
    ...userStyle,
    top: `${displayTop}%`,
    height: `${displayHeight}%`,
    width: `${style.width}%`,
    [rtl ? "right" : "left"]: `${style.xOffset}%`,
  }

  return (
    <div
      ref={eventRef}
      data-event
      tabIndex={0}
      title={tooltip || title}
      onClick={(e) => {
        if (isDragging) return
        e.stopPropagation()
        onSelect?.(event, e)
      }}
      onDoubleClick={(e) => {
        if (isDragging) return
        e.stopPropagation()
        onDoubleClick?.(event, e)
      }}
      onKeyDown={handleKeyDown}
      onPointerDown={handleMovePointerDown}
      onPointerMove={handleMovePointerMove}
      onPointerUp={handleMovePointerUp}
      style={inlineStyle}
      className={cn(
        "absolute z-10 overflow-hidden rounded-md border px-1.5 py-0.5 text-xs leading-tight",
        isBackgroundEvent
          ? "bg-calendar-event/20 border-calendar-event/30 text-foreground pointer-events-none z-0"
          : "bg-calendar-event text-calendar-event-foreground border-calendar-event/50",
        "hover:opacity-90 transition-opacity",
        "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring",
        isSelectedEvent && "ring-2 ring-ring z-20",
        continuesPrior && "rounded-t-none border-t-0",
        continuesAfter && "rounded-b-none border-b-0",
        canDrag && !isBackgroundEvent && "cursor-grab active:cursor-grabbing",
        isDragging && "opacity-70 ring-2 ring-primary z-30 shadow-lg",
        userClassName,
      )}
    >
      {EventComponent ? (
        <EventComponent
          event={event}
          title={title}
          localizer={localizer}
          continuesPrior={continuesPrior}
          continuesAfter={continuesAfter}
        />
      ) : (
        <div className="flex flex-col gap-0">
          {label && (
            <span className="text-[10px] font-normal opacity-80 truncate">{label}</span>
          )}
          <span className="font-medium truncate">{title}</span>
        </div>
      )}

      {/* ── Resize handle (bottom edge) ── */}
      {canResize && !isBackgroundEvent && !continuesAfter && (
        <div
          data-resize-handle="true"
          onPointerDown={handleResizePointerDown}
          onPointerMove={handleResizePointerMove}
          onPointerUp={handleResizePointerUp}
          className={cn(
            "absolute bottom-0 left-0 right-0 h-2 cursor-s-resize z-40",
            "after:content-[''] after:absolute after:bottom-0.5 after:left-1/2 after:-translate-x-1/2",
            "after:w-6 after:h-0.5 after:rounded-full after:bg-current after:opacity-0",
            "hover:after:opacity-40",
          )}
        />
      )}
    </div>
  )
}

"use client"

import * as React from "react"
import * as PopoverPrimitive from "@radix-ui/react-popover"
import { cn } from "@/lib/utils"
import type {
  CalendarEvent,
  Accessors,
  Getters,
  DateLocalizer,
  CalendarComponents,
} from "../types"
import { EventCell } from "./event-cell"

export interface EventPopupProps<TEvent extends CalendarEvent = CalendarEvent> {
  events: TEvent[]
  date: Date
  open: boolean
  onOpenChange: (open: boolean) => void
  anchorRef: React.RefObject<HTMLElement | null>
  accessors: Accessors<TEvent>
  getters: Getters<TEvent>
  localizer: DateLocalizer
  components: CalendarComponents<TEvent>
  selected?: TEvent
  onSelect?: (event: TEvent, e: React.SyntheticEvent) => void
  onDoubleClick?: (event: TEvent, e: React.SyntheticEvent) => void
  onKeyPress?: (event: TEvent, e: React.KeyboardEvent) => void
}

export function EventPopup<TEvent extends CalendarEvent = CalendarEvent>({
  events,
  date,
  open,
  onOpenChange,
  anchorRef,
  accessors,
  getters,
  localizer,
  components,
  selected,
  onSelect,
  onDoubleClick,
  onKeyPress,
}: EventPopupProps<TEvent>) {
  const label = localizer.format(date, "dayHeaderFormat")

  return (
    <PopoverPrimitive.Root open={open} onOpenChange={onOpenChange}>
      <PopoverPrimitive.Anchor
        ref={anchorRef as React.RefObject<HTMLDivElement>}
        className="absolute"
      />
      <PopoverPrimitive.Portal>
        <PopoverPrimitive.Content
          align="start"
          sideOffset={4}
          className={cn(
            "z-50 w-60 max-h-80 overflow-y-auto rounded-lg border border-border bg-popover p-3 shadow-lg",
            "data-[state=open]:animate-in data-[state=closed]:animate-out",
            "data-[state=closed]:fade-out-0 data-[state=open]:fade-in-0",
            "data-[state=closed]:zoom-out-95 data-[state=open]:zoom-in-95",
          )}
        >
          <div className="mb-2">
            <span className="text-sm font-semibold text-foreground">{label}</span>
          </div>
          <div className="flex flex-col gap-1">
            {events.map((event, idx) => (
              <EventCell
                key={idx}
                event={event}
                selected={selected}
                accessors={accessors}
                getters={getters}
                localizer={localizer}
                components={components}
                onSelect={onSelect}
                onDoubleClick={onDoubleClick}
                onKeyPress={onKeyPress}
              />
            ))}
          </div>
        </PopoverPrimitive.Content>
      </PopoverPrimitive.Portal>
    </PopoverPrimitive.Root>
  )
}

"use client"

import * as React from "react"
import { cn } from "@/lib/utils"
import type {
  CalendarEvent,
  Accessors,
  Getters,
  DateLocalizer,
  CalendarComponents,
  EventSegment,
} from "../types"
import { EventCell } from "./event-cell"

// ─── EventRow ──────────────────────────────────────────────────────

export interface EventRowProps<TEvent extends CalendarEvent = CalendarEvent> {
  segments: EventSegment<TEvent>[]
  slotMetrics: {
    slots: number
    range: Date[]
  }
  className?: string
  accessors: Accessors<TEvent>
  getters: Getters<TEvent>
  localizer: DateLocalizer
  components: CalendarComponents<TEvent>
  selected?: TEvent
  onSelect?: (event: TEvent, e: React.SyntheticEvent) => void
  onDoubleClick?: (event: TEvent, e: React.SyntheticEvent) => void
  onKeyPress?: (event: TEvent, e: React.KeyboardEvent) => void
  isAllDay?: boolean
}

export function EventRow<TEvent extends CalendarEvent = CalendarEvent>({
  segments,
  slotMetrics,
  className,
  accessors,
  getters,
  localizer,
  components,
  selected,
  onSelect,
  onDoubleClick,
  onKeyPress,
  isAllDay,
}: EventRowProps<TEvent>) {
  let lastEnd = 1
  const totalSlots = slotMetrics.slots

  const row: React.ReactNode[] = []
  for (const { event, left, right, span } of segments) {
    const gap = left - lastEnd
    if (gap > 0) {
      row.push(
        <div
          key={`gap-${lastEnd}`}
          className="flex-none"
          style={{ flexBasis: `${(gap / totalSlots) * 100}%` }}
        />,
      )
    }
    row.push(
      <div
        key={`evt-${left}-${accessors.title(event)}`}
        className="flex-none px-0.5"
        style={{ flexBasis: `${(span / totalSlots) * 100}%` }}
      >
        <EventCell
          event={event}
          selected={selected}
          isAllDay={isAllDay}
          continuesPrior={left === 1}
          continuesAfter={right === totalSlots}
          accessors={accessors}
          getters={getters}
          localizer={localizer}
          components={components}
          slotStart={slotMetrics.range[left - 1]}
          slotEnd={slotMetrics.range[right - 1]}
          onSelect={onSelect}
          onDoubleClick={onDoubleClick}
          onKeyPress={onKeyPress}
        />
      </div>,
    )
    lastEnd = left + span
  }

  return (
    <div className={cn("flex flex-row items-stretch", className)}>
      {row}
    </div>
  )
}

// ─── EventEndingRow (handles "show more") ──────────────────────────

export interface EventEndingRowProps<TEvent extends CalendarEvent = CalendarEvent>
  extends EventRowProps<TEvent> {
  maxRows: number
  onShowMore?: (events: TEvent[], date: Date, cell: HTMLElement, slot: number) => void
}

export function EventEndingRow<TEvent extends CalendarEvent = CalendarEvent>({
  segments,
  slotMetrics,
  maxRows,
  className,
  accessors,
  getters,
  localizer,
  components,
  selected,
  onSelect,
  onDoubleClick,
  onKeyPress,
  isAllDay,
  onShowMore,
}: EventEndingRowProps<TEvent>) {
  let lastEnd = 1
  const totalSlots = slotMetrics.slots

  const row: React.ReactNode[] = []
  for (const { event, left, right, span } of segments) {
    const gap = left - lastEnd
    if (gap > 0) {
      row.push(
        <div
          key={`gap-${lastEnd}`}
          className="flex-none"
          style={{ flexBasis: `${(gap / totalSlots) * 100}%` }}
        />,
      )
    }
    row.push(
      <div
        key={`evt-${left}-${accessors.title(event)}`}
        className="flex-none px-0.5"
        style={{ flexBasis: `${(span / totalSlots) * 100}%` }}
      >
        <EventCell
          event={event}
          selected={selected}
          isAllDay={isAllDay}
          continuesPrior={left === 1}
          continuesAfter={right === totalSlots}
          accessors={accessors}
          getters={getters}
          localizer={localizer}
          components={components}
          slotStart={slotMetrics.range[left - 1]}
          slotEnd={slotMetrics.range[right - 1]}
          onSelect={onSelect}
          onDoubleClick={onDoubleClick}
          onKeyPress={onKeyPress}
        />
      </div>,
    )
    lastEnd = left + span
  }

  return (
    <div className={cn("flex flex-row items-stretch", className)}>
      {row}
    </div>
  )
}

