"use client"

import * as React from "react"
import { useRef, useEffect, useCallback } from "react"
import { cn } from "@/lib/utils"
import type { CalendarEvent, DateLocalizer, Getters } from "../types"
import { useDnD } from "../hooks/use-dnd"

export interface BackgroundCellsProps<TEvent extends CalendarEvent = CalendarEvent> {
  range: Date[]
  date?: Date
  getNow: () => Date
  getters: Getters<TEvent>
  localizer: DateLocalizer
  selectable?: boolean | "ignoreEvents"
  longPressThreshold?: number
  onSelectSlot?: (slotInfo: {
    start: Date
    end: Date
    slots: Date[]
    action: "click" | "doubleClick" | "select"
    bounds?: DOMRect
    box?: { x: number; y: number; clientX: number; clientY: number }
  }) => void
  resourceId?: string | number
}

export function BackgroundCells<TEvent extends CalendarEvent = CalendarEvent>({
  range,
  date,
  getNow,
  getters,
  localizer,
  selectable,
  onSelectSlot,
  resourceId,
}: BackgroundCellsProps<TEvent>) {
  const containerRef = useRef<HTMLDivElement>(null)
  const [selecting, setSelecting] = React.useState(false)
  const [selectStart, setSelectStart] = React.useState<number | null>(null)
  const [selectEnd, setSelectEnd] = React.useState<number | null>(null)

  const now = getNow()
  const currentDate = date || now

  const handleCellClick = useCallback(
    (idx: number) => {
      if (!selectable) return
      const slot = range[idx]
      const slotEnd = localizer.add(slot, 1, "day")
      onSelectSlot?.({
        start: slot,
        end: slotEnd,
        slots: [slot],
        action: "click",
      })
    },
    [selectable, range, localizer, onSelectSlot],
  )

  const handleCellDoubleClick = useCallback(
    (idx: number) => {
      if (!selectable) return
      const slot = range[idx]
      const slotEnd = localizer.add(slot, 1, "day")
      onSelectSlot?.({
        start: slot,
        end: slotEnd,
        slots: [slot],
        action: "doubleClick",
      })
    },
    [selectable, range, localizer, onSelectSlot],
  )

  const handleMouseDown = useCallback(
    (idx: number) => {
      if (!selectable) return
      setSelecting(true)
      setSelectStart(idx)
      setSelectEnd(idx)
    },
    [selectable],
  )

  const handleMouseEnter = useCallback(
    (idx: number) => {
      if (!selecting) return
      setSelectEnd(idx)
    },
    [selecting],
  )

  useEffect(() => {
    if (!selecting) return
    const handleMouseUp = () => {
      if (selectStart !== null && selectEnd !== null) {
        const start = Math.min(selectStart, selectEnd)
        const end = Math.max(selectStart, selectEnd)
        const slots = range.slice(start, end + 1)
        onSelectSlot?.({
          start: slots[0],
          end: localizer.add(slots[slots.length - 1], 1, "day"),
          slots,
          action: "select",
        })
      }
      setSelecting(false)
      setSelectStart(null)
      setSelectEnd(null)
    }
    window.addEventListener("mouseup", handleMouseUp)
    return () => window.removeEventListener("mouseup", handleMouseUp)
  }, [selecting, selectStart, selectEnd, range, localizer, onSelectSlot])

  const isInSelection = (idx: number) => {
    if (!selecting || selectStart === null || selectEnd === null) return false
    const start = Math.min(selectStart, selectEnd)
    const end = Math.max(selectStart, selectEnd)
    return idx >= start && idx <= end
  }

  // ── DnD: month view drop target ──
  const { dragState, updatePreview, endDrag } = useDnD()
  const [dropTarget, setDropTarget] = React.useState<number | null>(null)

  const handleDragEnterCell = useCallback(
    (idx: number) => {
      if (!dragState) return
      setDropTarget(idx)
      const slot = range[idx]
      const event = dragState.event
      const evtStart = dragState.resolvedStart ?? (event as Record<string, unknown>).start as Date | undefined
      const evtEnd = dragState.resolvedEnd ?? (event as Record<string, unknown>).end as Date | undefined
      if (!evtStart || !evtEnd) return
      const duration = evtEnd.getTime() - evtStart.getTime()
      // Preserve time-of-day, move to new date
      const newStart = new Date(slot)
      newStart.setHours(evtStart.getHours(), evtStart.getMinutes(), evtStart.getSeconds(), 0)
      const newEnd = new Date(newStart.getTime() + duration)
      updatePreview(newStart, newEnd, resourceId)
    },
    [dragState, range, updatePreview, resourceId],
  )

  const handleDragDropCell = useCallback(
    (_idx: number) => {
      if (!dragState) return
      endDrag()
      setDropTarget(null)
    },
    [dragState, endDrag],
  )

  return (
    <div ref={containerRef} className="flex flex-row absolute inset-0">
      {range.map((slot, idx) => {
        const isToday = localizer.isSameDate(slot, now)
        const isOffRange = !localizer.isSameDate(slot, currentDate, "month")
        const { className: userClassName, style: userStyle } =
          getters.dayProp?.(slot) ?? {}

        return (
          <div
            key={idx}
            className={cn(
              "flex-1 border-l border-border/50 first:border-l-0",
              isToday && "bg-calendar-today",
              isOffRange && "bg-calendar-off-range",
              isInSelection(idx) && "bg-calendar-selected/30",
              dragState && dropTarget === idx && "bg-primary/10 ring-1 ring-primary/30 ring-inset",
              selectable && "cursor-cell",
              userClassName,
            )}
            style={userStyle}
            onClick={() => handleCellClick(idx)}
            onDoubleClick={() => handleCellDoubleClick(idx)}
            onMouseDown={() => handleMouseDown(idx)}
            onMouseEnter={() => {
              handleMouseEnter(idx)
              handleDragEnterCell(idx)
            }}
            onMouseUp={() => handleDragDropCell(idx)}
          />
        )
      })}
    </div>
  )
}

"use client"

import * as React from "react"
import { useMemo } from "react"
import { cn } from "@/lib/utils"
import type {
  CalendarEvent,
  Accessors,
  Getters,
  DateLocalizer,
  CalendarComponents,
} from "../types"
import { getDateSlotMetrics } from "../lib/date-slot-metrics"
import { BackgroundCells } from "./background-cells"
import { EventRow } from "./event-row"
import { DateHeader } from "./headers"

export interface DateContentRowProps<TEvent extends CalendarEvent = CalendarEvent> {
  range: Date[]
  date: Date
  events: TEvent[]
  backgroundEvents?: TEvent[]
  maxRows?: number
  renderHeader: (props: {
    date: Date
    key: string
    className?: string
  }) => React.ReactNode
  renderForMeasure?: boolean
  getNow: () => Date
  selected?: TEvent
  selectable?: boolean | "ignoreEvents"
  longPressThreshold?: number
  isAllDay?: boolean
  accessors: Accessors<TEvent>
  getters: Getters<TEvent>
  localizer: DateLocalizer
  components: CalendarComponents<TEvent>
  onSelect?: (event: TEvent, e: React.SyntheticEvent) => void
  onDoubleClick?: (event: TEvent, e: React.SyntheticEvent) => void
  onKeyPress?: (event: TEvent, e: React.KeyboardEvent) => void
  onSelectSlot?: (slotInfo: {
    start: Date
    end: Date
    slots: Date[]
    action: string
    bounds?: DOMRect
    box?: { x: number; y: number }
  }) => void
  onShowMore?: (events: TEvent[], date: Date, cell: HTMLElement, slot: number) => void
  resourceId?: string | number
  rtl?: boolean
}

export function DateContentRow<TEvent extends CalendarEvent = CalendarEvent>({
  range,
  date,
  events,
  backgroundEvents = [],
  maxRows = 5,
  renderHeader,
  renderForMeasure,
  getNow,
  selected,
  selectable,
  longPressThreshold,
  isAllDay,
  accessors,
  getters,
  localizer,
  components,
  onSelect,
  onDoubleClick,
  onKeyPress,
  onSelectSlot,
  onShowMore,
  resourceId,
}: DateContentRowProps<TEvent>) {
  const metrics = useMemo(
    () =>
      getDateSlotMetrics({
        range,
        events,
        maxRows,
        minRows: 0,
        accessors,
        localizer,
      }),
    [range, events, maxRows, accessors, localizer],
  )

  const { levels, extra } = metrics

  return (
    <div className={cn("relative", "min-h-25")}>
      {/* Background cells (selection, today, off-range) */}
      <BackgroundCells
        range={range}
        date={date}
        getNow={getNow}
        getters={getters}
        localizer={localizer}
        selectable={selectable}
        longPressThreshold={longPressThreshold}
        onSelectSlot={onSelectSlot}
        resourceId={resourceId}
      />

      {/* Header row - date numbers */}
      <div className="relative flex flex-row">
        {range.map((d, idx) => {
          const isToday = localizer.isSameDate(d, getNow())
          const isOffRange = !localizer.isSameDate(d, date, "month")
          return (
            <div key={idx} className="flex-1 text-center py-1">
              {renderHeader ? (
                renderHeader({ date: d, key: `hdr-${idx}` })
              ) : (
                <DateHeader
                  date={d}
                  label={localizer.format(d, "dateFormat")}
                  isToday={isToday}
                  isOffRange={isOffRange}
                  drilldownView="day"
                />
              )}
            </div>
          )
        })}
      </div>

      {/* Event rows */}
      <div className="relative">
        {levels.map((segs, idx) => (
          <EventRow
            key={idx}
            segments={segs}
            slotMetrics={{ slots: range.length, range }}
            accessors={accessors}
            getters={getters}
            localizer={localizer}
            components={components}
            selected={selected}
            onSelect={onSelect}
            onDoubleClick={onDoubleClick}
            onKeyPress={onKeyPress}
            isAllDay={isAllDay}
          />
        ))}

        {/* Show more */}
        {extra.length > 0 && (
          <div className="flex flex-row">
            {range.map((d, idx) => {
              const eventsForDay = extra.filter((seg) =>
                localizer.inRange(d, accessors.start(seg.event), accessors.end(seg.event), "day"),
              )
              if (eventsForDay.length === 0) {
                return <div key={idx} className="flex-1" />
              }
              return (
                <div key={idx} className="flex-1 px-0.5">
                  <button
                    type="button"
                    className="w-full text-xs text-primary font-medium hover:underline text-left px-1"
                    onClick={(e) => {
                      const cell = e.currentTarget.parentElement
                      onShowMore?.(
                        eventsForDay.map((s) => s.event),
                        d,
                        cell as HTMLElement,
                        idx,
                      )
                    }}
                  >
                    +{eventsForDay.length} more
                  </button>
                </div>
              )
            })}
          </div>
        )}
      </div>
    </div>
  )
}

"use client"

import * as React from "react"
import { useRef, useMemo, useCallback } from "react"
import { cn } from "@/lib/utils"
import type {
  CalendarEvent,
  Accessors,
  Getters,
  DateLocalizer,
  CalendarComponents,
  DayLayoutAlgorithm,
} from "../types"
import { getStyledEvents } from "../lib/day-event-layout"
import { getTimeSlotMetrics } from "../lib/time-slot-metrics"
import { TimeGridEvent } from "./event-cell"
import { TimeSlotGroup } from "./time-slots"
import * as dates from "../lib/dates"
import { useDnD } from "../hooks/use-dnd"

export interface DayColumnProps<TEvent extends CalendarEvent = CalendarEvent> {
  date: Date
  events: TEvent[]
  backgroundEvents?: TEvent[]
  step: number
  timeslots: number
  min: Date
  max: Date
  getNow: () => Date
  selected?: TEvent
  selectable?: boolean | "ignoreEvents"
  longPressThreshold?: number
  isNow?: boolean
  accessors: Accessors<TEvent>
  getters: Getters<TEvent>
  localizer: DateLocalizer
  components: CalendarComponents<TEvent>
  rtl?: boolean
  resource?: string | number
  dayLayoutAlgorithm?: DayLayoutAlgorithm
  onSelectSlot?: (slotInfo: {
    start: Date
    end: Date
    slots: Date[]
    action: string
    resourceId?: string | number
  }) => void
  onSelect?: (event: TEvent, e: React.SyntheticEvent) => void
  onDoubleClick?: (event: TEvent, e: React.SyntheticEvent) => void
  onKeyPress?: (event: TEvent, e: React.KeyboardEvent) => void
}

export function DayColumn<TEvent extends CalendarEvent = CalendarEvent>({
  date,
  events,
  backgroundEvents = [],
  step,
  timeslots,
  min,
  max,
  getNow,
  selected,
  selectable,
  isNow,
  accessors,
  getters,
  localizer,
  components,
  rtl,
  resource,
  dayLayoutAlgorithm,
  onSelectSlot,
  onSelect,
  onDoubleClick,
  onKeyPress,
}: DayColumnProps<TEvent>) {
  const columnRef = useRef<HTMLDivElement>(null)

  const slotMetrics = useMemo(
    () => getTimeSlotMetrics({ min, max, step, timeslots, localizer }),
    [min, max, step, timeslots, localizer],
  )

  const styledEvents = useMemo(
    () =>
      getStyledEvents({
        events,
        accessors: accessors as Accessors<CalendarEvent>,
        slotMetrics,
        minimumStartDifference: Math.ceil((step * timeslots) / 2),
        dayLayoutAlgorithm: dayLayoutAlgorithm ?? "overlap",
      }),
    [events, accessors, slotMetrics, step, timeslots, dayLayoutAlgorithm],
  )

  const styledBackground = useMemo(
    () =>
      getStyledEvents({
        events: backgroundEvents,
        accessors: accessors as Accessors<CalendarEvent>,
        slotMetrics,
        minimumStartDifference: 0,
        dayLayoutAlgorithm: "no-overlap",
      }),
    [backgroundEvents, accessors, slotMetrics],
  )

  // Build time slot groups for rendering
  const groups = useMemo(() => {
    const result: Date[][] = []
    const totalMin = 1 + localizer.getTotalMin(min, max)
    const minutesFromMidnight = localizer.getMinutesFromMidnight(min)
    const numGroups = Math.ceil((totalMin - 1) / (step * timeslots))

    for (let grp = 0; grp < numGroups; grp++) {
      const group: Date[] = []
      for (let slot = 0; slot < timeslots; slot++) {
        const slotIdx = grp * timeslots + slot
        group.push(localizer.getSlotDate(min, minutesFromMidnight, slotIdx * step))
      }
      result.push(group)
    }
    return result
  }, [min, max, step, timeslots, localizer])

  // Current time indicator
  const now = getNow()
  const showCurrentTime = isNow && dates.inRange(now, min, max, "minutes")
  const currentTimePosition = showCurrentTime
    ? ((dates.diff(min, now, "minutes") / dates.diff(min, max, "minutes")) * 100)
    : null

  // Click handler for slots
  const handleSlotClick = useCallback(
    (e: React.MouseEvent<HTMLDivElement>) => {
      if (!selectable) return
      if ((e.target as HTMLElement).closest("[data-event]")) return

      const bounds = columnRef.current?.getBoundingClientRect()
      if (!bounds) return
      const y = e.clientY - bounds.top
      const pct = y / bounds.height
      const totalMinutes = dates.diff(min, max, "minutes")
      const minuteOffset = Math.round(pct * totalMinutes / step) * step
      const slotDate = dates.add(min, minuteOffset, "minutes")
      const slotEnd = dates.add(slotDate, step, "minutes")

      onSelectSlot?.({
        start: slotDate,
        end: slotEnd,
        slots: [slotDate],
        action: "click",
        resourceId: resource,
      })
    },
    [selectable, min, max, step, resource, onSelectSlot],
  )

  const { className: dayClassName, style: dayStyle } = getters.dayProp?.(date) ?? {}

  // ── DnD: detect when a dragged event hovers over this column ──
  const { dragState, updatePreview, endDrag } = useDnD<TEvent>()
  const [isHoveredDragTarget, setIsHoveredDragTarget] = React.useState(false)

  const handleColumnPointerMove = useCallback(
    (e: React.PointerEvent) => {
      if (!dragState || dragState.action !== "move") return
      setIsHoveredDragTarget(true)
      // Only respond if this column doesn't already own the event (cross-column drag)
      const bounds = columnRef.current?.getBoundingClientRect()
      if (!bounds) return
      const pct = Math.max(0, Math.min(1, (e.clientY - bounds.top) / bounds.height))
      const totalMinutes = dates.diff(min, max, "minutes")
      const minuteOffset = Math.round((pct * totalMinutes) / step) * step

      // Build new start/end on this column's date
      const dayStart = new Date(date)
      dayStart.setHours(min.getHours(), min.getMinutes(), 0, 0)
      const newStart = dates.add(dayStart, minuteOffset, "minutes")
      const evtStart = accessors.start(dragState.event as unknown as TEvent)
      const evtEnd = accessors.end(dragState.event as unknown as TEvent)
      const duration = evtEnd.getTime() - evtStart.getTime()
      const newEnd = new Date(newStart.getTime() + duration)

      updatePreview(newStart, newEnd, resource)
    },
    [dragState, min, max, step, date, resource, updatePreview, accessors],
  )

  const handleColumnPointerUp = useCallback(
    (_e: React.PointerEvent) => {
      if (!dragState) return
      endDrag()
      setIsHoveredDragTarget(false)
    },
    [dragState, endDrag],
  )

  return (
    <div
      ref={columnRef}
      className={cn(
        "relative flex-1 border-l border-border/50 first:border-l-0",
        isHoveredDragTarget && "bg-primary/5",
        dayClassName,
      )}
      style={dayStyle}
      onClick={handleSlotClick}
      onPointerMove={handleColumnPointerMove}
      onPointerUp={handleColumnPointerUp}
      onPointerLeave={() => setIsHoveredDragTarget(false)}
    >
      {/* Time slot background grid */}
      {groups.map((group, idx) => (
        <TimeSlotGroup
          key={idx}
          group={group}
          getters={getters}
          resourceId={resource}
        />
      ))}

      {/* Background events */}
      {styledBackground.map(({ event, style }, idx) => (
        <TimeGridEvent
          key={`bg-${idx}`}
          event={event as unknown as TEvent}
          style={style}
          isBackgroundEvent
          accessors={accessors}
          getters={getters}
          localizer={localizer}
          components={components}
          rtl={rtl}
        />
      ))}

      {/* Foreground events */}
      {styledEvents.map(({ event, style }, idx) => {
        const evt = event as unknown as TEvent
        const start = accessors.start(evt)
        const end = accessors.end(evt)
        const label = localizer.format({ start, end }, "eventTimeRangeFormat")
        const continuesPrior = localizer.lt(start, min, "day")
        const continuesAfter = localizer.gt(end, max, "day")

        return (
          <TimeGridEvent
            key={`evt-${idx}`}
            event={evt}
            label={label}
            style={style}
            selected={selected}
            continuesPrior={continuesPrior}
            continuesAfter={continuesAfter}
            accessors={accessors}
            getters={getters}
            localizer={localizer}
            components={components}
            rtl={rtl}
            columnDate={date}
            columnMin={min}
            columnMax={max}
            step={step}
            resource={resource}
            onSelect={onSelect}
            onDoubleClick={onDoubleClick}
            onKeyPress={onKeyPress}
          />
        )
      })}

      {/* Current time indicator */}
      {showCurrentTime && currentTimePosition !== null && (
        <div
          className="absolute left-0 right-0 z-30 border-t-2 border-calendar-current-time pointer-events-none"
          style={{ top: `${currentTimePosition}%` }}
        >
          <div className="absolute -left-1.5 -top-1.5 w-3 h-3 rounded-full bg-calendar-current-time" />
        </div>
      )}
    </div>
  )
}

