  onSelectSlot,
  onSelect,
  onDoubleClick,
  onKeyPress,
  onDrillDown,
}: TimeGridProps<TEvent>) {
  const contentRef = useRef<HTMLDivElement>(null)
  const headerScrollRef = useRef<HTMLDivElement>(null)
  const gutterRef = useRef<HTMLDivElement>(null)
  const [isOverflowing, setIsOverflowing] = useState(false)

  const now = getNow()

  // Default min/max: start of day to end of day
  const min = useMemo(() => {
    if (minProp) return minProp
    const d = new Date(range[0])
    d.setHours(0, 0, 0, 0)
    return d
  }, [minProp, range])

  const max = useMemo(() => {
    if (maxProp) return maxProp
    const d = new Date(range[0])
    d.setHours(23, 59, 59, 999)
    return d
  }, [maxProp, range])

  // Partition events into all-day and time-based
  const { allDayEvents, rangeEvents } = useMemo(() => {
    const allDay: TEvent[] = []
    const ranged: TEvent[] = []
    for (const event of events) {
      if (accessors.allDay(event) || localizer.diff(accessors.start(event), accessors.end(event), "day") >= 1) {
        allDay.push(event)
      } else {
        ranged.push(event)
      }
    }
    return { allDayEvents: allDay, rangeEvents: ranged }
  }, [events, accessors, localizer])

  // Resources
  const resourceData = useMemo(() => {
    if (!resourcesProp || resourcesProp.length === 0) return null
    return Resources(
      resourcesProp as any,
      accessors,
    )
  }, [resourcesProp, accessors])

  // Group events by date then resource
  const getEventsForDate = useCallback(
    (date: Date, resourceId?: string | number) => {
      return rangeEvents.filter((event) => {
        const start = accessors.start(event)
        const end = accessors.end(event)
        if (!dates.inRange(date, start, end, "day")) return false
        if (resourceId !== undefined && resourceAccessor) {
          const eventResource =
            typeof resourceAccessor === "function"
              ? resourceAccessor(event)
              : (event as Record<string, unknown>)[resourceAccessor as string]
          return eventResource === resourceId
        }
        return true
      })
    },
    [rangeEvents, accessors, resourceAccessor],
  )

  const getBackgroundEventsForDate = useCallback(
    (date: Date, resourceId?: string | number) => {
      return backgroundEvents.filter((event) => {
        const start = accessors.start(event)
        const end = accessors.end(event)
        if (!dates.inRange(date, start, end, "day")) return false
        if (resourceId !== undefined && resourceAccessor) {
          const eventResource =
            typeof resourceAccessor === "function"
              ? resourceAccessor(event)
              : (event as Record<string, unknown>)[resourceAccessor as string]
          return eventResource === resourceId
        }
        return true
      })
    },
    [backgroundEvents, accessors, resourceAccessor],
  )

  // Scroll to time on mount
  useEffect(() => {
    if (!contentRef.current) return
    const target = scrollToTime || now
    const totalMinutes = dates.diff(min, max, "minutes")
    const targetMinutes = dates.diff(min, target, "minutes")
    const pct = targetMinutes / totalMinutes
    contentRef.current.scrollTop = pct * contentRef.current.scrollHeight
  }, []) // eslint-disable-line react-hooks/exhaustive-deps

  // Sync header scroll with content scroll
  const handleScroll = useCallback(() => {
    if (contentRef.current && headerScrollRef.current) {
      headerScrollRef.current.scrollLeft = contentRef.current.scrollLeft
    }
  }, [])

  // Check overflow
  useEffect(() => {
    if (!contentRef.current) return
    setIsOverflowing(contentRef.current.scrollHeight > contentRef.current.clientHeight)
  }, [range, events])

  return (
    <div className="flex flex-col h-full">
      {/* Fixed header with all-day events */}
      <TimeGridHeader
        range={range}
        events={allDayEvents}
        getNow={getNow}
        accessors={accessors}
        getters={getters}
        localizer={localizer}
        components={components}
        selected={selected}
        selectable={selectable}
        isOverflowing={isOverflowing}
        rtl={rtl}
        resources={resourcesProp}
        scrollRef={headerScrollRef}
        onSelectSlot={onSelectSlot}
        onSelect={onSelect}
        onDoubleClick={onDoubleClick}
        onKeyPress={onKeyPress}
        onDrillDown={onDrillDown}
      />

      {/* Scrollable time content */}
      <div
        ref={contentRef}
        className="flex-1 overflow-y-auto overflow-x-hidden"
        onScroll={handleScroll}
      >
        <div className="flex flex-row min-h-full">
          {/* Time gutter */}
          <TimeGutter
            min={min}
            max={max}
            step={step}
            timeslots={timeslots}
            localizer={localizer}
            getNow={getNow}
            gutterRef={gutterRef}
          />

          {/* Day columns */}
          <div className="flex flex-row flex-1 min-w-0">
            {resourceData
              ? resourceData.map(([resourceId, _resource]: [string | number | typeof NONE, unknown]) => {
                  return range.map((date, idx) => {
                    return (
                      <DayColumn
                        key={`${String(resourceId)}-${idx}`}
                        date={date}
                        events={getEventsForDate(date, resourceId as string | number)}
                        backgroundEvents={getBackgroundEventsForDate(date, resourceId as string | number)}
                        step={step}
                        timeslots={timeslots}
                        min={min}
                        max={max}
                        getNow={getNow}
                        selected={selected}
                        selectable={selectable}
                        isNow={localizer.isSameDate(date, now)}
                        accessors={accessors}
                        getters={getters}
                        localizer={localizer}
                        components={components}
                        rtl={rtl}
                        resource={resourceId as string | number}
                        dayLayoutAlgorithm={dayLayoutAlgorithm}
                        onSelectSlot={onSelectSlot}
                        onSelect={onSelect}
                        onDoubleClick={onDoubleClick}
                        onKeyPress={onKeyPress}
                      />
                    )
                  })
                })
              : range.map((date, idx) => (
                  <DayColumn
                    key={idx}
                    date={date}
                    events={getEventsForDate(date)}
                    backgroundEvents={getBackgroundEventsForDate(date)}
                    step={step}
                    timeslots={timeslots}
                    min={min}
                    max={max}
                    getNow={getNow}
                    selected={selected}
                    selectable={selectable}
                    isNow={localizer.isSameDate(date, now)}
                    accessors={accessors}
                    getters={getters}
                    localizer={localizer}
                    components={components}
                    rtl={rtl}
                    dayLayoutAlgorithm={dayLayoutAlgorithm}
                    onSelectSlot={onSelectSlot}
                    onSelect={onSelect}
                    onDoubleClick={onDoubleClick}
                    onKeyPress={onKeyPress}
                  />
                ))}
          </div>
        </div>
      </div>
    </div>
  )
}

"use client"

import * as React from "react"
import { cn } from "@/lib/utils"
import type {
  CalendarEvent,
  Accessors,
  Getters,
  DateLocalizer,
  CalendarComponents,
} from "../types"
import { DateContentRow } from "./date-content-row"
import { Header } from "./headers"

export interface TimeGridHeaderProps<TEvent extends CalendarEvent = CalendarEvent> {
  range: Date[]
  events: TEvent[]
  width?: number
  getNow: () => Date
  accessors: Accessors<TEvent>
  getters: Getters<TEvent>
  localizer: DateLocalizer
  components: CalendarComponents<TEvent>
  selected?: TEvent
  selectable?: boolean | "ignoreEvents"
  isOverflowing?: boolean
  rtl?: boolean
  resources?: { id: string | number; title: string }[]
  scrollRef?: React.RefObject<HTMLDivElement | null>
  onSelectSlot?: (slotInfo: {
    start: Date
    end: Date
    slots: Date[]
    action: string
    resourceId?: string | number
  }) => void
  onSelect?: (event: TEvent, e: React.SyntheticEvent) => void
  onDoubleClick?: (event: TEvent, e: React.SyntheticEvent) => void
  onKeyPress?: (event: TEvent, e: React.KeyboardEvent) => void
  onDrillDown?: (date: Date, view: string) => void
}

export function TimeGridHeader<TEvent extends CalendarEvent = CalendarEvent>({
  range,
  events,
  getNow,
  accessors,
  getters,
  localizer,
  components,
  selected,
  selectable,
  isOverflowing,
  resources,
  scrollRef,
  onSelectSlot,
  onSelect,
  onDoubleClick,
  onKeyPress,
  onDrillDown,
}: TimeGridHeaderProps<TEvent>) {
  const HeaderComponent = components.header ?? Header

  return (
    <div
      ref={scrollRef}
      className={cn(
        "border-b border-border bg-background sticky top-0 z-20",
        isOverflowing && "overflow-y-scroll",
      )}
    >
      {/* Day headers */}
      <div className="flex flex-row">
        {/* Gutter spacer */}
        <div className="w-16 shrink-0 border-r border-border" />

        {resources && resources.length > 0 ? (
          // Resource columns
          resources.map((resource) => (
            <div key={resource.id} className="flex-1 min-w-0">
              <div className="flex flex-row">
                {range.map((date, idx) => {
                  const label = localizer.format(date, "dayFormat")
                  return (
                    <div key={idx} className="flex-1 text-center py-1.5 border-l border-border/50 first:border-l-0">
                      <div className="text-[10px] text-muted-foreground">{resource.title}</div>
                      <HeaderComponent
                        date={date}
                        label={label}
                        localizer={localizer}
                      />
                    </div>
                  )
                })}
              </div>
            </div>
          ))
        ) : (
          // Regular day headers
          range.map((date, idx) => {
            const label = localizer.format(date, "dayFormat")
            return (
              <div
                key={idx}
                className="flex-1 text-center py-1.5 border-l border-border/50 first:border-l-0"
              >
                <button
                  type="button"
                  title={label}
                  className={cn(
                    "inline-flex flex-col items-center gap-0.5",
                    "hover:text-primary transition-colors",
                  )}
                  onClick={() => onDrillDown?.(date, "day")}
                >
                  <HeaderComponent
                    date={date}
                    label={label}
                    localizer={localizer}
                  />
                </button>
              </div>
            )
          })
        )}
      </div>

      {/* All-day events row */}
      {events.length > 0 && (
        <div className="flex flex-row border-t border-border/50">
          <div className="w-16 shrink-0 border-r border-border flex items-center justify-end pr-2">
            <span className="text-[10px] text-muted-foreground">all-day</span>
          </div>
          <div className="flex-1 min-w-0">
            <DateContentRow
              range={range}
              date={range[0]}
              events={events}
              maxRows={3}
              getNow={getNow}
              selected={selected}
              selectable={selectable}
              isAllDay
              accessors={accessors}
              getters={getters}
              localizer={localizer}
              components={components}
              onSelect={onSelect}
              onDoubleClick={onDoubleClick}
              onKeyPress={onKeyPress}
              onSelectSlot={onSelectSlot}
              renderHeader={() => null}
            />
          </div>
        </div>
      )}
    </div>
  )
}

"use client"

import * as React from "react"
import { cn } from "@/lib/utils"
import type { DateLocalizer } from "../types"

export interface TimeSlotGroupProps {
  group: Date[]
  resource?: unknown
  renderSlot?: (value: Date, index: number) => React.ReactNode
  getters?: {
    slotProp?: (date: Date, resourceId?: string | number) => {
      className?: string
      style?: React.CSSProperties
    }
  }
  resourceId?: string | number
}

export function TimeSlotGroup({
  group,
  renderSlot,
  getters,
  resourceId,
}: TimeSlotGroupProps) {
  return (
    <div className="flex flex-col border-b border-border/50 min-h-10">
      {group.map((value, idx) => {
        const slotProps = getters?.slotProp?.(value, resourceId) ?? {}
        return (
          <div
            key={idx}
            className={cn(
              "flex-1",
              idx > 0 && "border-t border-border/30 border-dashed",
              slotProps.className,
            )}
            style={slotProps.style}
          >
            {renderSlot?.(value, idx)}
          </div>
        )
      })}
    </div>
  )
}

export interface TimeGutterProps {
  min: Date
  max: Date
  step: number
  timeslots: number
  localizer: DateLocalizer
  getNow: () => Date
  resource?: unknown
  gutterRef?: React.Ref<HTMLDivElement>
}

export function TimeGutter({
  min,
  max,
  step,
  timeslots,
  localizer,
  getNow,
  gutterRef,
}: TimeGutterProps) {
  const totalMin = 1 + localizer.getTotalMin(min, max)
  const minutesFromMidnight = localizer.getMinutesFromMidnight(min)
  const numGroups = Math.ceil((totalMin - 1) / (step * timeslots))

  const groups: Date[][] = []
  for (let grp = 0; grp < numGroups; grp++) {
    const group: Date[] = []
    for (let slot = 0; slot < timeslots; slot++) {
      const slotIdx = grp * timeslots + slot
      const minFromStart = slotIdx * step
      group.push(localizer.getSlotDate(min, minutesFromMidnight, minFromStart))
    }
    groups.push(group)
  }

  return (
    <div ref={gutterRef} className="flex flex-col w-16 shrink-0 border-r border-border select-none">
      {groups.map((group, idx) => (
        <TimeSlotGroup
          key={idx}
          group={group}
          renderSlot={(value, slotIdx) =>
            slotIdx === 0 ? (
              <span className="block -mt-2.5 pr-2 text-right text-[11px] text-muted-foreground whitespace-nowrap">
                {localizer.format(value, "timeGutterFormat")}
              </span>
            ) : null
          }
        />
      ))}
    </div>
  )
}

"use client"

import * as React from "react"
import { useState, useCallback, useEffect } from "react"
import {
  Sheet,
  SheetContent,
  SheetHeader,
  SheetTitle,
  SheetDescription,
  SheetFooter,
  SheetClose,
} from "@/components/ui/sheet"
import { cn } from "@/lib/utils"
import type { CalendarEvent, EventDetailSheetProps, DateLocalizer } from "../types"

// ─── Helpers ──────────────────────────────────────────────────────
function formatTime(date: Date, localizer: DateLocalizer, culture?: string): string {
  try {
    return localizer.format(date, "h:mm a" as any, culture)
  } catch {
    return date.toLocaleTimeString([], { hour: "numeric", minute: "2-digit" })
  }
}

function formatDate(date: Date, localizer: DateLocalizer, culture?: string): string {
  try {
    return localizer.format(date, "EEEE, MMMM d, yyyy" as any, culture)
  } catch {
    return date.toLocaleDateString([], { weekday: "long", month: "long", day: "numeric", year: "numeric" })
  }
}

function formatInputDate(date: Date): string {
  const y = date.getFullYear()
  const m = String(date.getMonth() + 1).padStart(2, "0")
  const d = String(date.getDate()).padStart(2, "0")
  return `${y}-${m}-${d}`
}

function formatInputTime(date: Date): string {
  const h = String(date.getHours()).padStart(2, "0")
  const min = String(date.getMinutes()).padStart(2, "0")
  return `${h}:${min}`
}

// ─── Default Event Detail Sheet ───────────────────────────────────
export function EventDetailSheet<TEvent extends CalendarEvent = CalendarEvent>({
  event,
  open,
  onOpenChange,
  title,
  start,
  end,
  isAllDay,
  localizer,
  onSave,
  onDelete,
  children,
  side = "right",
}: EventDetailSheetProps<TEvent>) {
  // Editing state
  const [isEditing, setIsEditing] = useState(false)
  const [editTitle, setEditTitle] = useState(title)
  const [editDescription, setEditDescription] = useState(
    (event as Record<string, unknown>).desc as string ||
    (event as Record<string, unknown>).description as string ||
    "",
  )
  const [editDate, setEditDate] = useState(formatInputDate(start))
  const [editStartTime, setEditStartTime] = useState(formatInputTime(start))
  const [editEndTime, setEditEndTime] = useState(formatInputTime(end))
  const [editAllDay, setEditAllDay] = useState(isAllDay)
  const [validationError, setValidationError] = useState<string | null>(null)

  // Reset edit state when event changes
  useEffect(() => {
    setEditTitle(title)
    setEditDescription(
      (event as Record<string, unknown>).desc as string ||
      (event as Record<string, unknown>).description as string ||
      "",
    )
    setEditDate(formatInputDate(start))
    setEditStartTime(formatInputTime(start))
    setEditEndTime(formatInputTime(end))
    setEditAllDay(isAllDay)
    setIsEditing(false)
    setValidationError(null)
  }, [event, title, start, end, isAllDay])

  const handleSave = useCallback(() => {
    if (!onSave) return

    // Parse date+time back
    const [yr, mo, dy] = editDate.split("-").map(Number)
    const [sh, sm] = editStartTime.split(":").map(Number)
    const [eh, em] = editEndTime.split(":").map(Number)

    const newStart = new Date(yr, mo - 1, dy, editAllDay ? 0 : sh, editAllDay ? 0 : sm)
    const newEnd = new Date(yr, mo - 1, dy, editAllDay ? 23 : eh, editAllDay ? 59 : em)

    // Validate: end must not be before start
    if (!editAllDay && newEnd <= newStart) {
      setValidationError("End time must be after start time.")
      return
    }
    setValidationError(null)

    const updated = {
      ...event,
      title: editTitle,
      desc: editDescription || undefined,
      description: editDescription || undefined,
      start: newStart,
      end: newEnd,
      allDay: editAllDay,
    } as TEvent

    onSave(updated, event)
    setIsEditing(false)
  }, [event, editTitle, editDescription, editDate, editStartTime, editEndTime, editAllDay, onSave])

  const handleDelete = useCallback(() => {
    onDelete?.(event)
    onOpenChange(false)
  }, [event, onDelete, onOpenChange])

  // Extra fields from the event (location, attendees, category, color, etc.)
  const location = (event as Record<string, unknown>).location as string | undefined
  const attendees = (event as Record<string, unknown>).attendees as string[] | undefined
  const category = (event as Record<string, unknown>).category as string | undefined
  const color = (event as Record<string, unknown>).color as string | undefined

  const timeDisplay = isAllDay
    ? "All day"
    : `${formatTime(start, localizer)} – ${formatTime(end, localizer)}`

  const dateDisplay = formatDate(start, localizer)

  return (
    <Sheet open={open} onOpenChange={onOpenChange}>
      <SheetContent side={side} className="flex flex-col overflow-y-auto">
        <SheetHeader>
          {/* Color accent bar */}
          {color && (
            <div
              className="h-1.5 w-full rounded-full -mt-1 mb-1"
              style={{ backgroundColor: color }}
            />
          )}

          {isEditing ? (
            <input
              type="text"
              value={editTitle}
              onChange={(e) => setEditTitle(e.target.value)}
              className={cn(
                "w-full rounded-md border border-input bg-transparent px-3 py-2 text-lg font-semibold",
                "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring",
              )}
              autoFocus
            />
          ) : (
            <SheetTitle className="text-lg">{title}</SheetTitle>
          )}

          <SheetDescription>
            {isEditing ? (
              <div className="space-y-3 mt-1">
                {/* Validation error */}
                {validationError && (
                  <p className="text-sm font-medium text-destructive" role="alert">
                    {validationError}
                  </p>
                )}

                {/* Date */}
                <div>
                  <label htmlFor="sheet-edit-date" className="text-xs font-medium text-muted-foreground block mb-1">Date</label>
                  <input
                    id="sheet-edit-date"
                    type="date"
                    value={editDate}
                    onChange={(e) => setEditDate(e.target.value)}
                    className={cn(
                      "w-full rounded-md border border-input bg-transparent px-3 py-1.5 text-sm",
                      "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring",
                    )}
                  />
                </div>

                {/* All-day toggle */}
                <label htmlFor="sheet-edit-allday" className="flex items-center gap-2 cursor-pointer">
                  <input
                    id="sheet-edit-allday"
                    type="checkbox"
                    checked={editAllDay}
                    onChange={(e) => setEditAllDay(e.target.checked)}
                    className="rounded border-input accent-primary"
                  />
                  <span className="text-sm">All day</span>
                </label>

                {/* Time range (hidden if all-day) */}
                {!editAllDay && (
                  <div className="grid grid-cols-2 gap-2">
                    <div>
                      <label htmlFor="sheet-edit-start-time" className="text-xs font-medium text-muted-foreground block mb-1">Start</label>
                      <input
                        id="sheet-edit-start-time"
                        type="time"
                        value={editStartTime}
                        onChange={(e) => setEditStartTime(e.target.value)}
                        className={cn(
                          "w-full rounded-md border border-input bg-transparent px-3 py-1.5 text-sm",
                          "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring",
                        )}
                      />
                    </div>
                    <div>
                      <label htmlFor="sheet-edit-end-time" className="text-xs font-medium text-muted-foreground block mb-1">End</label>
                      <input
                        id="sheet-edit-end-time"
                        type="time"
                        value={editEndTime}
                        onChange={(e) => setEditEndTime(e.target.value)}
                        className={cn(
                          "w-full rounded-md border border-input bg-transparent px-3 py-1.5 text-sm",
                          "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring",
                        )}
                      />
                    </div>
                  </div>
                )}

                {/* Description */}
                <div>
                  <label htmlFor="sheet-edit-description" className="text-xs font-medium text-muted-foreground block mb-1">Description</label>
                  <textarea
                    id="sheet-edit-description"
                    value={editDescription}
                    onChange={(e) => setEditDescription(e.target.value)}
                    rows={3}
                    placeholder="Add a description..."
                    className={cn(
                      "w-full rounded-md border border-input bg-transparent px-3 py-1.5 text-sm resize-none",
                      "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring",
                    )}
                  />
                </div>
              </div>
            ) : (
              <div className="space-y-3 mt-1">
                {/* Date & Time */}
                <div className="flex items-center gap-2 text-sm">
                  <svg className="h-4 w-4 shrink-0 text-muted-foreground" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={1.5}>
                    <path strokeLinecap="round" strokeLinejoin="round" d="M6.75 3v2.25M17.25 3v2.25M3 18.75V7.5a2.25 2.25 0 012.25-2.25h13.5A2.25 2.25 0 0121 7.5v11.25m-18 0A2.25 2.25 0 005.25 21h13.5A2.25 2.25 0 0021 18.75m-18 0v-7.5A2.25 2.25 0 015.25 9h13.5A2.25 2.25 0 0121 11.25v7.5" />
                  </svg>
                  <div>
                    <span className="text-foreground">{dateDisplay}</span>
                    <span className="text-muted-foreground block">{timeDisplay}</span>
                  </div>
                </div>

                {/* Description */}
                {!!(editDescription || (event as Record<string, unknown>).desc || (event as Record<string, unknown>).description) && (
                  <div className="flex items-start gap-2 text-sm">
                    <svg className="h-4 w-4 shrink-0 mt-0.5 text-muted-foreground" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={1.5}>
                      <path strokeLinecap="round" strokeLinejoin="round" d="M19.5 14.25v-2.625a3.375 3.375 0 00-3.375-3.375h-1.5A1.125 1.125 0 0113.5 7.125v-1.5a3.375 3.375 0 00-3.375-3.375H8.25m0 12.75h7.5m-7.5 3H12M10.5 2.25H5.625c-.621 0-1.125.504-1.125 1.125v17.25c0 .621.504 1.125 1.125 1.125h12.75c.621 0 1.125-.504 1.125-1.125V11.25a9 9 0 00-9-9z" />
                    </svg>
                    <p className="text-foreground/80">
                      {(event as Record<string, unknown>).desc as string || (event as Record<string, unknown>).description as string}
                    </p>
                  </div>
                )}

                {/* Location */}
                {location && (
                  <div className="flex items-center gap-2 text-sm">
                    <svg className="h-4 w-4 shrink-0 text-muted-foreground" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={1.5}>
